window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]=window.__LIBQ["the-gioi-hoan-my"]["q02"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]["cotTruyen"]=[{"chuong":101,"tieuDe":"Một Búa Quật Ngã","tomTat":"Nhóc tỳ trinh sát hang Hắc hổ Thú Vương ở khu đất trống sát khí dày đặc rồi rút lui vì quá nguy hiểm; qua chữ ghi niên đại cạnh Hắc Sát Liên nó xác nhận Thú Vương do Bổ Thiên các hàng phục để trấn thủ. Nó dùng cự thạch phủ phù văn khiêu khích sáu bảy con bá chủ mãnh thú tạo thành thú triều hỗn loạn, dụ Hắc hổ rời hang, rồi phóng vào đào trộm Hắc Sát Liên và bỏ chạy, bôi chất lỏng lên hai con Thanh Lang để xóa dấu vết. Chìm đáy sông tu hành suốt đêm luyện hóa dược tính, nó mở khẩu thứ sáu Động Thiên khi mới 9 tuổi rưỡi. Quay lại chiến trường thứ hai tan hoang, nó gặp liên minh nhỏ bại trận than về Tiêu Thiên quá cường đại. Tiêu Thiên — thanh niên áo bào bạc thu 16 khối Bổ Thiên thạch, thắng cả thiếu niên Mộc tộc — vẫn bất an vì một đứa nhỏ giấu mặt từng bị hắn đánh lén. Nhóc tỳ ẩn thân ra tay, dùng Bạch cốt đại bổng như búa đánh hai đòn sau gáy, khiến kẻ mạnh nhất hơn chín vạn người bị một búa quật ngã."},{"chuong":102,"tieuDe":"Thật Đáng Thương","tomTat":"Nhóc tỳ dùng Bạch cốt đại bổng đánh lén Tiêu Thiên — thiếu niên áo bào bạc được xưng thiên hạ đệ nhất thiên tài — ngất hai búa để báo thù việc từng bị đánh lén lúc bị Cổ Ngạc đuổi giết, rồi lục soát cướp 25 khối Bổ Thiên thạch cùng 2 bình bảo đan. Tiêu Thiên tỉnh dậy đau đầu dữ dội, mọc cục u như sừng trên trán và nhận ra kẻ tấn công là đứa nhỏ hắn từng đánh chưởng cướp Bổ Thiên thạch. Tin khu thứ tám bạo động lan truyền: phù cốt bị cướp sạch khiến trận vực mất hiệu lực, tổ đoàn hơn 8900 người xông cửa ải cuối thành công, các thiếu niên nhận ra phong cách tên nhóc siêu quậy ở Hư Thần giới. Bổ Thiên các nhượng bộ, Hùng Phi và Trác Vân trưởng lão cùng tộc lão cắn răng cho phép 3000 người thông qua. Nhóc tỳ lo bị lộ danh tính nên chạy trốn ngược qua khu thứ ba, rồi gặp lại Tiêu Thiên, đánh lén lần hai nện lên cục u chưa lành và ném trả bao Bổ Thiên thạch đã mất hiệu lực, dặn cả vốn lẫn lời phải hoàn lại. Cuối cùng nó tiện tay nhặt lại một Đế tử bị bỏ sót rồi than mình đáng thương, cô đơn xoay người hướng về khu thứ tám."},{"chuong":103,"tieuDe":"Thần Vũ Ngút Trời","tomTat":"Không cam lòng rời đi, Thạch Hạo trong lốt nhóc tỳ khắc lên tảng đá cứng dòng chữ 'Thần vũ ngút trời, quang minh chính đại' cùng câu khoe về cây búa, rồi đánh xuyên tấm chắn phù văn khu thứ tám, đuổi hung cầm chiếm tổ chim mà ngủ. Sáng hôm sau nó gặp hai huynh muội đang nướng chim, cướp ăn rồi dò hỏi và bật cười khi biết Bổ Thiên Các đã bày thiên la địa võng phong tỏa chiến trường thứ hai để bắt chính 'thằng ranh nhân thần cộng phẫn' là nó, còn cho người ngoài xem lễ. Trước khi chia tay, nó tặng hai huynh muội mỗi người một viên Long Tán và Hổ Dược lột được từ Tiêu Thiên. Vì lần này tuyển ba nghìn môn đồ nên độ khó cửa ải hạ thấp, nhóc tỳ trà trộn vào một tổ đội xông ra rồi lách vào chiến trường thứ hai, khiến các trưởng lão Hùng Phi và Trác Vân cay đắng thề tính sổ. Ở chiến trường thứ hai, Tiêu Thiên tỉnh dậy trong khe đá bị bịt kín, phát hiện hơn hai mươi viên Bổ Thiên Thạch bị cướp nay được trả lại đầy đủ nhưng bản thân vẫn bị đập búa đến mọc một cục u như sừng trên trán. Hắn phẫn uất nổi điên thi triển Âm Ba Công, tiếng rống chấn động sơn hà khiến các trưởng lão tưởng lầm là kỳ tài ngút trời mà tranh nhau khen ngợi. Cuối cùng Trác Vân hé lộ Bổ Thiên Các sở hữu một gốc linh dược chăm bằng Hắc Hổ Sát, tương lai có thể lột xác thành Thánh Dược, dùng để oai chấn tứ phương chiêu mộ thiên tài."},{"chuong":104,"tieuDe":"Ung Dung Bình Tĩnh","tomTat":"Đám tiền bối các thế lực khiếp phục khi hay tin Bổ Thiên Các gây trồng được Thánh Dược, thứ có thể cải tử hoàn sinh vốn cực hiếm ở Đại Hoang, nên nôn nóng chờ được chiêm ngưỡng. Hùng Phi trưởng lão dẫn mọi người đi ngắm các thiếu niên tài tuấn trước, gặp Tiêu Thiên áo bạc phong thái siêu phàm, nhưng khi hắn quay lại lộ ra cục u to như sừng trên trán khiến các trưởng lão phải khéo léo gọi đó là 'thiên tướng' để không đắc tội. Tiêu Thiên ném ra túi da thú chứa 28 viên Bổ Thiên Thạch, đứng đầu bảng, được tán tụng là hạt giống đáng bồi dưỡng, dù trong lòng hắn căm hận vì bị kẻ trong bóng tối nện hai búa gây nên cục u. Đi tiếp, đoàn phát hiện dãy núi khu thứ tám bị tàn phá tan hoang, nghe kể về một bóng người bí ẩn chủ động khiêu khích các hung thú bá chủ gây thú triều rồi dẫm bật qua cả đỉnh núi, khiến các trưởng lão nổi giận quyết truy tìm thằng siêu quậy. Trác Vân trưởng lão vẫn ung dung khuyên mọi người giữ hình tượng, rồi dẫn đoàn tới hố đất do Hắc Hổ Sát canh giữ để giới thiệu Thánh Dược Hắc Sát Liên đã 800 năm tuổi sắp lột xác. Nhưng khi giơ tay chỉ, ông chết lặng nhận ra Hắc Sát Liên đã bị đào sạch cả gốc lẫn ngọn, chỉ còn cái hố trống, khiến vẻ điềm tĩnh sụp đổ và hóa thành cơn cuồng nộ như người điên."},{"chuong":105,"tieuDe":"Khảo Nghiệm Kết Thúc","tomTat":"Trác Vân trưởng lão của Bổ Thiên các đang hiền hòa tiếp khách bỗng phát điên gào thét khi phát hiện Hắc Sát Liên trong địa quật đã biến mất, các trưởng lão hốt hoảng lục soát trước sự chê cười của đám khách mời. Hắc hổ khổng lồ từ địa quật bước ra tỏa sát khí, truyền thần niệm cảnh báo đây là kế điệu hổ ly sơn rồi lui vào bóng tối. Hùng Phi và các trưởng lão nhanh chóng quy tội cho nhóc tỳ siêu quậy từng náo loạn Hư Thần Giới, xác nhận qua cái hố nhảy đặc trưng và mảnh linh dược in dấu răng nhỏ, hóa ra bảo dược đã bị nhai sống cả gốc chỉ để đột phá đệ lục Động Thiên. Bổ Thiên các bày thiên la địa võng phong tỏa chiến trường thứ hai, huy động toàn bộ đệ tử nhưng chỉ tìm được sáu trong mười tám bộ bảo cốt bị giấu, trong khi nhóc tỳ đã đổi hình dạng trà trộn giữa ba ngàn đệ tử. Các trưởng lão đành tuyên bố khảo nghiệm kết thúc, mắt lóe xanh dò xét từng thiên tài vì nghi kẻ trộm lẩn trong đó, đồng thời suy đoán hắn là ấu tể của thái cổ hung thú hóa hình người. Một thiếu niên áo bào bạc ôm thù kẻ đập mình hai búa lại bị đám đông hiểu lầm là anh hùng tâm tính siêu phàm khi ngửa mặt nhìn trời. Cuối cùng Bổ Thiên các công bố kết nạp toàn bộ người vượt qua làm đệ tử, ban truyền thừa Thượng cổ Tịnh thổ, đoàn người tiến về sơn môn nơi Thạch Nghị cùng nhóm quyền quý đã chờ sẵn cho nghi thức nhập môn."},{"chuong":106,"tieuDe":"Tội phạm truy nã của Tịnh Thổ","tomTat":"Sau khi các tộc lão Đại Hoang ly biệt con em, ba ngàn thiếu niên qua khảo nghiệm được dẫn vào Bổ Thiên các nơi Thượng cổ Tịnh Thổ, trong khi gần chín vạn người bị loại. Nhóc tỳ - vốn là nhân vật chính đã biến hình thành mập ục ịch - giả khóc bám vào một cụ già xa lạ để trà trộn nhập môn, rồi lập tức bỏ đi khi vừa được an ủi. Nó quấy nhiễu khắp nơi, thèm ăn linh cầm linh dược, dò hỏi về con gái Nhân Hoàng và Trùng Đồng giả cùng những nhân vật lai lịch lớn đã rời đi sớm. Khi nghi thức bái Tổ sư vừa xong, một tảng đá nghi là Tế Linh được đưa tới, hiện lên hai câu chữ khiêu khích do chính Nhóc siêu quậy để lại, khiến ba ngàn người kinh hoảng nhận ra kẻ khét tiếng. Trưởng lão Hùng Phi phát lệnh truy nã ngay trong nội bộ, buộc Nhóc tỳ phải trốn vào đám đông và giả vờ hô bắt chính mình, rồi trớ trêu bị chính Hùng Phi và Trác Vân - hai người từng bị nó chọc đến hộc máu - chọn làm đệ tử. Được thiếu nữ áo trắng an trí ở khu núi đá và học văn tự Hoàn Cốt, Nhóc tỳ giả vui nhưng trong lòng ưu sầu, lại được dặn tránh xa Tế Cư của Tế Linh. Cuối cùng, không thấy Bóng Lông đâu suốt mấy ngày, nó phát hiện Thanh Phong bị thương đầy máu ứ, âm thầm nổi giận và quyết hỏi cho ra lẽ dù đang phải cẩn trọng giữa Bổ Thiên các."},{"chuong":107,"tieuDe":"Vô Đề","tomTat":"Cả Hư Thần giới bàn tán sôi nổi về nhóc tỳ khi nó đào Bảo Cốt khu thứ tám, trộm Bảo Dược và lưu tảng đá khắc ‘Búa Ở Trong Tay, Ta Có Thiên Hạ’ ở chiến trường thứ hai; Hùng Phi và Trác Vân trưởng lão tức phun máu, phát lệnh truy nã, còn khối u trên đầu Tiêu Thiên bị đồn là do nhóc tỳ nện búa khiến hắn suýt nổi khùng. Ở khu núi đá cạnh rừng trúc, nhóc tỳ làm đệ tử mới phải xách nước linh tuyền, khai thác quặng tinh kim, bất mãn vì hai lão già chỉ dạy thứ nó đã biết; một thiếu niên giải thích chỉ người thiên phú nghịch thiên mới được truyền Cốt Văn và Bảo Thuật. Bóng Lông trở về sau nhiều ngày, bị nhóc tỳ tóm đuôi, kể chuyện lang thang Linh sơn khí lành nguy hiểm mới hái được một cây linh thảo, rồi được sai đi điều tra Thanh Phong. Thanh Phong ngồi một mình tự xử vết thương, bị bọn thiếu niên thiên tài trong thiên tài doanh đánh bầm nửa người và cấy Phù Văn chạy loạn phá tu hành nhằm đào thải nó để thế chỗ, nhưng nó quyết kiên trì tới đầu tháng lấy Dược Tán và Cốt Thư, đồng thời ghi nhớ kinh văn Tế Linh giúp tiểu ca ca. Bóng Lông lén tới thăm, nghe kể mọi chuyện rồi về báo sau nửa đêm; nhóc tỳ mặt đen kịt vạch kế trừng trị, nghi chỗ dựa của bọn kia là Vũ gia Thạch Quốc và tính lôi kéo Thạch Nghị vào cuộc. Hai ngày sau, một đám thiên tài của thiên tài doanh — tuấn kiệt các bộ tộc lớn — kéo tới vùng núi đá để phô diễn sự chênh lệch cho đệ tử mới, đúng thời điểm nhóc tỳ hẹn ra tay."},{"chuong":108,"tieuDe":"Thiên Tài Doanh","tomTat":"Nhóm thiên tài đưa hơn ba ngàn đệ tử mới tới rừng trúc khu nhập môn. Vũ Phong ra mặt kêu gọi hòa khí, nhiều đệ tử mới thách đấu nhưng đều bại: thiên tài áo xám dùng tường Linh hỏa thiêu Thải Cưu, thiên tài cao to phô Kim Tuyền Ba Văn Công xoắn nát trường mâu. Tiêu Thiên một chiêu thắng rồi nổi gân xanh cố nhịn kích động. Chu Vũ Hào giả bộ sư huynh ôn hòa nhưng dùng Ngư Long Phù Văn kèm ám kình đánh trọng thương Thanh Phong đến ngũ tạng bể nát, rồi mượn cớ khơi thông huyết mạch hại thêm lần nữa. Nhóc tỳ trốn trong đám đông quan sát, thấy Thanh Phong bị hại thì ra tay đấm Chu Vũ Hào nở hoa mặt, hô hoán vu hắn là đồng bọn nhóc siêu quậy, kích động mấy trăm đệ tử đuổi đánh đến răng bay hộc máu. Có người hỏi vì sao Thạch Nghị cùng con gái Nhân Hoàng và hơn chục kỳ tài đặc biệt không xuất hiện, được đáp là bị lão quái vật đưa đi."},{"chuong":109,"tieuDe":"Xung Đột Đẫm Máu","tomTat":"Chu Vũ Hào bị mấy trăm rồi hơn ngàn thiếu niên các bộ lạc đánh hội đồng vì trước đó tự nhận biết chỗ nhóc siêu quậy rồi bỏ chạy; một Phù Chưởng thần bí đánh gãy xương sườn trái hắn, khiến hắn ngã xuống bị giẫm đạp gãy hết răng. Hai người thân của Chu Vũ Hào nhảy vào cứu cũng bị Phù Chưởng đánh gãy xương. Thạch Hạo trà trộn trong đám đệ tử mới hô hào kích động, ra quyền đầu và ra tay trọng thương ba người rồi lui về sau đắc ý, biến vụ việc thành nội chiến hơn ba ngàn người dùng Phù Văn đối kháng. Một ông lão ngồi trước sơn môn triệu hồ lô vỏ vàng từ hư không nuốt hết bão táp như cá voi hút nước, ra lệnh kẻ cầm đầu diện bích ba năm rồi rời đi. Trưởng lão Hùng Phi và Trác Vân điều tra nhưng không tìm ra kẻ cầm đầu, chỉ có mấy kẻ xui xẻo bị thương nặng; Trác Vân chửi mắng Chu Vũ Hào rồi cả hai thu hồi Khuyển Ma Công. Sư tỷ tiết lộ hồ lô là chí bảo Bổ Thiên các do Tế Linh (một giàn dây hồ lô) kết ra. Vài ngày sau, Thạch Hạo đi khắp Bổ Thiên các mênh mông và nhìn thấy Thạch Nghị đang bước trên con đường không tận cùng vào Thượng Cổ Thánh Viện, cộng hưởng đại đạo và được lợi ích lớn dù chưa vào."},{"chuong":110,"tieuDe":"Tế Linh Của Tịnh Thổ","tomTat":"Nhóc tỳ từ bỏ ý định vào Thượng Cổ Thánh Viện khi biết nơi ấy mấy chục đến mấy trăm năm mới mở một lần cho một người, lần này Bổ Thiên các đã chọn Thạch Nghị, đồng thời thoáng thấy một thiếu niên như thần đang bước trên con đường vào Thánh Viện. Nắm đuôi Bóng Lông, nó rón rén lẻn vào khu vườn cổ hơn trăm dặm nơi Tế Linh ở ẩn, khu vực không ai dám tới gần. Càng vào trong đất càng hoang vu hóa sa mạc vì bị một luồng sức mạnh ma quái hút mất địa khí, khiến thần hi trong người nó bộc phát Phù Văn dày đặc; nó đoán Tế Linh đang tu bí công hút địa khí nuốt thiên tinh. Đến khu vườn cổ ba tầng còn sót lại, nó thấy Tế Linh của Bổ Thiên các chỉ là một giàn dây hồ lô ố vàng ốm yếu sắp tàn nhưng vẫn uy nghiêm như thần linh, và dưới đám lá khô có một trái hồ lô màu xanh chứa khí Hỗn Độn khiến nó lẫn Bóng Lông muốn hái nhưng bị bản năng ngăn lại. Nó ngồi tu hành dưới Tế Linh, quán tưởng Nguyên Thủy Chân Giải và nhận ra khi Phù Văn hồ lô xanh lấp loé kèm thiên địa đạo âm thì việc lĩnh ngộ dễ dàng hơn nhiều. Khi rời đi, nó sởn tóc gáy chạm mặt một lão già tóc xám mắt trống rỗng, đầu bị cổ kiếm rỉ sét xuyên thủng, không sinh mệnh mà di chuyển như hư không, phát tiếng ô ô như khóc rồi chặn đứng đường đi của nó."},{"chuong":111,"tieuDe":"Chuyện Thần Quái Từ Thời Thượng Cổ","tomTat":"Tại nơi ở Tế Linh trong Thượng Cổ Tịnh Thổ, một ông lão tử khí Thượng Cổ tóc xám nhuốm máu đen, cổ kiếm rỉ sét cắm trên đầu, liên tục cản đường Thạch Hạo và tái tạo từ hư không mỗi khi bị né. Nhóc tỳ chạy về cầu cứu Tế Linh nhưng giàn dây hồ lô khô vàng bất động; khi định chạm trái hồ lô vỏ xanh, nó phát khí Hỗn Độn hiển hóa Phù Văn đẩy lui nó. Ông lão lặp lại “Trả kiếm cho ta”, nhóc tỳ hứa sau này tìm giúp trả kiếm khiến trời đất biến sắc sấm chớp, ông lão biến mất. Sáu ngày sau ông lão hiện lần hai bên giường, các đệ tử không nhìn thấy nhưng sờ được như tượng băng lạnh thấu xương, cả đám kinh hoàng bỏ chạy. Trưởng lão Hùng Phi và Trác Vân biến sắc, tiết lộ đây là chuyện thần quái Thượng Cổ cách mấy trăm năm xuất hiện một lần tất chết người, rồi chạy đi mời lão tiền bối. Cuối chương nhóc tỳ hết sợ, lại cưỡi lên cổ ông lão tóc xám; đồng thời một ông lão phương xa nâng hồ lô vàng óng đầy khí Hỗn Độn xuất hiện, khiến cao tầng Bổ Thiên các chấn động cùng xuất quan chạy tới."},{"chuong":112,"tieuDe":"Là Chết Hay Là Cơ Duyên","tomTat":"Nhóc tỳ giấu thân phận cưỡi trên cổ một vị thần quái Thượng Cổ bị cổ kiếm đâm xuyên đầu, dùng đỉnh đồng gõ leng keng đốm lửa tứ tung để nhổ thanh kiếm mà nó tưởng là Bảo Cụ chí cường, khiến hơn ba nghìn thiếu niên trợn mắt vì lá gan của nó. Đám trưởng lão Bổ Thiên các dẫn đầu là Đào Dã cầm hồ lô vàng óng khí Hỗn Độn bay tới giải cứu, nhưng nhóc tỳ tưởng họ tới cướp kiếm nên ôm chặt đề phòng. Trác Vân giải thích đây là thần quái Thượng Cổ, mỗi lần xuất hiện đều có người phải chết, khiến nhóc tỳ hoảng nhảy bám các trưởng lão suýt bóp Hùng Phi tắt thở. Cả đám hộ tống nó tới đại điện nghị sự Bổ Thiên các, nơi Đào Dã tiết lộ vị thần quái xưng Tử Thần cách mấy trăm năm xuất thế một lần cùng dịp Bách Đoạn sơn mở ra, ai bị Hắn chọn trúng mà không giúp được đều chết. Thanh kiếm cắm đầu Hắn là của đối thủ ngày xưa, còn kiếm thật của Hắn rơi mất ở Bách Đoạn sơn mạch cần nhóc tỳ tìm về nếu không sẽ chết. Đào Dã nói nay nơi đó khác xưa, chứa cơ duyên lớn, nếu Tử Thần chọn nhóc tỳ thì Bổ Thiên các được thêm một suất, ngay cả di chủng thuần huyết Li Long, Thao Thiết cũng đưa dòng dõi vào, khiến nhóc tỳ trợn mắt kinh ngạc."},{"chuong":113,"tieuDe":"Thân Phận Bại Lộ","tomTat":"Các nguyên lão Bổ Thiên các thuyết phục nhóc tỳ vào Bách Đoạn sơn, giải thích rằng đây là mảnh đất đầy cơ duyên nhưng chỉ người dưới mười tám tuổi mới vào được nên chúng buộc phải cậy nhờ nó. Nhóc tỳ cảnh giác, mặc cả đòi chỗ tốt và tuyên bố muốn bắt một con Kim Sí Đại Bằng non khiến cả đoàn cứng đơ. Khi được đưa xuống bàn bạc, bốn lão tiền bối mắt ánh xanh thử thân thể nó, nhưng nó phản kích một đấm chấn động cung điện, khiến các lão kinh ngạc khen thân thể nghịch thiên. Ngay lúc đó Hùng Phi nhận ra nó chính là 'thằng nhóc quỷ' từng gây loạn hại hắn và Trác Vân khốn đốn, thân phận bại lộ. Bốn lão dỗ dành và giao cho nó nhiệm vụ tìm Bất Lão thần tuyền mang về, đổi lại được khắc tên lên Bất Hủ Thần Bi và vào Tàng Kinh các chọn Bảo Thuật. Sau khi bị bắt quả tang trộm ăn Tuyết Ngọc Sâm rồi đổ cho Đào Dã 'cho', nó được thả tự do tu hành, rồi mang một cây linh dược nguyên vẹn tới Thiên tài doanh tặng 'đệ đệ' Thanh Phong. Nó công khai mở kèo đánh cược quanh cây linh dược, khiêu khích cả đám thiếu niên lẫn thiếu nữ; một thiếu nữ áo xanh cùng vài người khác lần lượt bước lên nhận khiêu chiến để đoạt lấy linh dược."},{"chuong":114,"tieuDe":"Vô Đề","tomTat":"Một đám thiên tài vây lấy nhóc tỳ ở Thiên tài doanh định dạy dỗ, nhưng nó bày trò “đổ chiến” cá cược buộc ai muốn đánh phải đặt chiến lợi phẩm xuống đất. Nhóc tỳ (Thạch Hạo) dùng Phù Văn hai tay dệt búa bạc đánh tan Khổng Tước xanh của Ngạn Tâm rồi khống chế bắt sống nàng, tạo cối xay bạc nghiền tan chiến mâu của Phiêu Tuyết. Nó đánh gục Chu Vũ Hào — kẻ trước khi hôn mê nhận ra nhóc tỳ chính là ca ca của Thanh Phong; rồi thắng liên tiếp 28 trận không ai địch nổi, chấn động toàn khu. Thạch Hạo công khai tuyên bố ai bắt nạt Thanh Phong là bắt nạt nó, khích lệ đệ đệ tu hành; Vũ Phong áo trắng được giục ra áp chế nhưng chỉ lắc đầu không xuất thủ. Sau nhiều ngày kết giao bạn bè, nhóc tỳ dặn dò Thanh Phong rồi lên đường tới Bách Đoạn sơn, nơi Đào Dã cho biết con gái Nhân hoàng, Thạch Nghị cùng hậu duệ Thái cổ di chủng đã được hộ tống đến trước. Các trưởng lão cảnh báo đệ tử về con non Thái Cổ hung thú và người đồng trang lứa mạnh không thể đánh bại, dặn phải tìm cách sống sót. Tại nơi ở của Tế Linh, các trưởng lão thu mảnh xương Thái cổ di chủng, rồi một hồ lô màu xanh hiện lên dựng thành thông đạo màu xanh; đoàn người đi vào và biến mất khỏi Bổ Thiên các."},{"chuong":115,"tieuDe":"Đoạn Không Thành","tomTat":"Đoàn Bổ Thiên các theo nguyên lão Đào Dã vượt qua con đường Thanh Kim do Tế Linh tạo ra, nơi thời gian như vỡ vụn và linh hồn tưởng chừng tách khỏi thân xác, rồi tiến vào Đoạn Không thành — một cổ thành di tích của cổ quốc từng huy hoàng nhưng đã suy tàn sau đại chiến. Đây là điểm tập kết trước khi Bách Đoạn sơn, nơi mấy trăm năm mới mở một lần, khai môn thu hút thiên kiêu khắp Đại Hoang. Trong thành, một nữ đệ tử lỡ lời khiến đoàn xung đột với tiểu Bạch Hổ của Tây Lăng thú sơn, buộc Đào Dã phải rút hồ lô Phù Văn xưng danh Bổ Thiên các để dằn mặt, đối phương hẹn quyết chiến trong Bách Đoạn sơn. Trên đường còn có Sở Hạ nhà Sở gia đến từ Hỏa quốc chào mời kết minh nhưng bị thiếu niên họ Cổ mỉa mai từ chối, rồi một thiếu niên nuôi Linh Tước năm màu thả yêu cầm nuốt sống mấy chục kẻ đang tranh đấu khiến cả phố lặng ngắt. Nhóc tỳ tinh nghịch dò la tin tức thì phát hiện mình bị nhiều thế lực truy lùng, có phe ra lệnh bắt sống, và đoán kẻ săn mình phần lớn là gia tộc đã mất Xích Vũ Bảo Phiến mà nó đang giữ. Giữa lúc đó, một Thái Cổ di chủng khổng lồ bay ngang che khuất mặt trời, phủ sát khí mênh mông, báo hiệu chinh chiến khốc liệt sắp diễn ra trong Bách Đoạn sơn nơi chôn giấu Bất Lão thần tuyền, truyền thừa Võ Thánh cùng vô số Thiên cốt và Thánh dược."},{"chuong":116,"tieuDe":"Bão Táp Tích Trữ","tomTat":"Đoạn Không thành náo nhiệt khi thiên tài các đại giáo và gia tộc cổ tề tựu, chuẩn bị tiến vào tiểu thế giới Bách Đoạn sơn. Nhóc tỳ giả dạng đi cùng đội năm thiên tài Bổ Thiên các, chạm trán Thái Cổ di chủng Phì Di, né được đòn đuôi rồi lớn tiếng cảnh cáo ngược khiến cả phố sững sờ, còn Phì Di thì cảm nhận từ nó một khí tức hung mãnh giống hệt mình. Trên đường, nó thấy đủ loại dị chủng kỳ lạ như người kim loại, đá biết nói, Liệt Thiên Ma Điệp, và được sư tỷ giải thích Bách Đoạn sơn thực chất là một tiểu thế giới. Tiền thưởng bắt đầu nó tăng gấp đôi, nhiều kẻ chịu đổi Bảo Cụ, Cốt Thư, Linh Dược để lấy đầu nó, có người suy đoán nó ẩn trong đội Bổ Thiên các nên chỉ cần bám theo. Tại tế đàn cổ của chư Thánh, một con Hoàng Kim sư tử chín đầu hống lên tuyên bố đã chọn 'kẻ nhân loại' kia làm nô bộc và cấm kẻ khác tranh giành. Cách đó tám ngàn dặm, Vũ tộc ở Hoàng Đô Thạch quốc dựa vào tin của Phong nhi cài trong Bổ Thiên các, xác định danh tính nó là Hạo Thiên, thấy nó có nét giống Thạch Tử Lăng năm xưa, liền ra lệnh sau khi vào Bách Đoạn sơn phải quấn lấy và có cơ hội thì diệt trừ không kiêng kỵ."},{"chuong":117,"tieuDe":"Bách Đoạn Sơn","tomTat":"Nửa tháng sau, biên giới tận cùng vùng đất bốc sương rồi nổ vang long trời; người già xác nhận thông đạo mở ra, Bách Đoạn Sơn — một tiểu thế giới độc lập cách nơi này bằng vô tận hư không — tái hiện thế gian. Các tiền bối báo đây là cơ may hiếm có: vào trong có thể chiếm đại cơ duyên hoặc chết không chỗ chôn thây, nơi này từng sản sinh Nhân hoàng và giáo chủ tối cao. Đoạn Không thành náo loạn khi mọi chủng tộc kéo tới, khí Hỗn Độn cuộn trào như sóng biển nhưng bị thành ngăn lại đúng như tên gọi. Muôn loài sinh linh tranh nhau lao vào sương mù, còn bao tải 「bảo bối」 của Nhóc Tỳ bị lộ chỉ là nồi niêu xoong chảo trưng dụng từ nhà bếp, khiến Đào Dã đen mặt vì mất danh Bổ Thiên các. Nhóm Bổ Thiên các qua cửa vào thông đạo, lao ra một tiểu thế giới linh khí đậm đặc gần đọng thành nước, có hồ trong, cổ dược và bốn gốc linh dược trên vách núi. Vừa vào rừng núi, Nhóc Tỳ đã tung hoành như rồng về biển: đụng gãy một cao thủ Thụ tộc hóa cây định đánh lén, rồi đuổi bắt chim lửa Đại Hồng và Nhân Hùng một sừng đen để làm đồ ăn. Các thiên tài Bổ Thiên các sững sờ, còn thiên tài các chủng tộc quanh đó kinh sợ lùi bước trước sự hung hãn của tiểu sư đệ."},{"chuong":118,"tieuDe":"Thằng Bé Hung Tàn","tomTat":"Một tiểu tử Nhân tộc thuộc Bổ Thiên các, được gọi là thằng bé hung tàn, truy đuổi Nhân Hùng một sừng màu đen để lấy tay gấu nhưng con mồi chạy thoát. Khi Hỏa Vân Tước nổi giận trút thác lửa, nó triệu khay bạc thần thánh chắn thế lửa rồi dùng Ma Cầm thời Thái Cổ, tia chớp vàng và vầng trăng bạc đánh cho con chim rớt thịt phải giả chết trốn đi. Nhóc tỳ nhặt hơn hai chục cân thịt đem nấu cùng sư huynh sư tỷ, ăn xong cả người phát sáng vì đó là huyết nhục bảo dược tăng tinh khí. Bên hồ nước có bốn gốc Xích Lan mọc trên vách núi, một sinh vật hình người ánh bạc khí tức lạnh giá xuất hiện, đạp sập vách đá thả cự thạch vạn cân định chôn vùi sư huynh đang hái dược, nhóc tỳ nhảy vào lôi người ra cứu. Kẻ ánh bạc đối chiếu bức tranh xác nhận nhắm đúng nhóc tỳ, ngắt sạch Linh dược rồi chiêu dụ nó làm chiến bộc, tự xưng là vương và chủ nhân của nó, hứa sau sẽ thả về Nhân tộc chiếm đất xưng vương. Nhưng nhóc tỳ chỉ đen mặt đi vòng quanh ngắm nghía, chê kẻ kia toàn xương lại là hình người khó ăn, bực tức tính chuyện chôn sống hay hấp cách thủy con mồi lạ này."},{"chuong":119,"tieuDe":"Thu Hoạch Di Chủng","tomTat":"Một sinh linh màu bạc (Thái Cổ di chủng hậu duệ Vương tộc) bị Thạch Hạo đòi ăn thịt nên tức giận thu ngân quang lộ chân thân thân người phủ vảy bạc, tự xưng “Vương tương lai” rồi lao vào đánh. Không địch nổi bằng sức thân thể, hắn vận Phù Văn cùng bảo phiến bạc và chủy thủ bạc, nhưng Thạch Hạo triển bảo thuật Toan Nghê Vương qua Cốt Kính phản chiếu ánh sáng làm hắn thủng bả vai. Thạch Hạo rút Cốt Tiễn vàng bẻ gãy chủy thủ, chặt đứt cánh tay trái rồi đuổi theo cắt cổ, đánh đầu lâu đối thủ thành tro. Nhặt được chiến lợi phẩm nhưng cây quạt bạc đã nát hơn nửa khiến Thạch Hạo bi phẫn, đồng môn kinh hãi vì độ giàu chí bảo của tiểu sư đệ. Không muốn ăn sinh linh hình người vì sợ ám ảnh, Thạch Hạo nghe sư huynh gợi ý bèn hô lớn rao đổi Thái Cổ di chủng, làm dãy núi rung động và có người đáp lại. Vượt một dãy núi, nhóm gặp hơn bốn mươi thiên tài hộ tống xe phượng đỏ thẫm — con gái nhỏ của Nhân Hoàng, sư muội cùng môn — và hai bên đồng ý thỏa thuận trao đổi."},{"chuong":120,"tieuDe":"Bảy Động Thiên","tomTat":"Nhóc tỳ rao trao đổi con sinh linh màu bạc mà nó chém giết; người mặc áo khoác đen giọng khàn từ chỗ xe kéo ra xác nhận đây là Linh Tộc, Thái Cổ di chủng cực hiếm có Vương huyết truyền thừa. Thiếu nữ hoàng tộc trong xe quyết đổi bằng Tử Vân Tâm — trái tim của Tử Vân Điêu mà nhóm thiên tài đã hao tổn chém giết — dù nhiều người can là không đáng. Nhóc tỳ trêu gọi công chúa là sư muội vì cùng Bổ Thiên các; thiếu nữ ~15-16 tuổi con gái được Nhân Hoàng sủng ái nhất vén rèm bước ra, lộ tên Hỏa Linh Nhi khi cười nhạo, rồi cả đám nhận ra đó là nhóc siêu quậy đang bị truy nã nên nhào tới vây bắt, nó bỏ chạy vào rừng biến mất. Vài ngày sau trong hang cổ, nhóc tỳ luyện hóa Tử Vân Tâm đột phá, mở ra miệng Động Thiên thứ bảy với dung nham cuồn cuộn chảy vào cơ thể, khí tức kinh khủng khiến mãnh thú chạy trốn. Nó bay tới khe núi nơi có xe kéo công chúa, đánh chết sinh linh mọc sừng người của Vũ Vương dám rủ nó làm tôi tớ, rồi bắn mười tia chớp giết luôn mấy Dị tộc còn lại. Cuối cùng công chúa Hỏa quốc kìm nén kích động chiêu mộ nhóc tỳ, tiết lộ đã liên hệ Hoàng Kim sư tử chín đầu, Vũ Vương, Ngân Huyết Cự Nhân để đi Thần Quật đoạt chí bảo; nhóc tỳ đồng ý nhưng ôm thù muốn hầm con sư tử dị dạng, rồi vỗ mông công chúa để trêu ngược lời dọa đánh mông của nàng."},{"chuong":121,"tieuDe":"Cảnh Ngộ","tomTat":"Hỏa Linh Nhi, công chúa Hỏa quốc và là sư muội ở Bổ Thiên các, nổi giận phun lửa hóa Chu Tước đánh nhóc tỳ, nhưng bị nó bung Nguyệt bàn màu bạc chắn lại và năm vị thiên tài can ngăn. Nàng ra điều kiện tha thứ là khi tới Thần Quật không được xung đột với Hoàng Kim sư tử chín đầu, nhưng nhóc tỳ lại chọc nàng 'giảm béo', khiến nàng phát điên dệt cánh Chu Tước truy sát, biến cả thảo nguyên thành biển lửa. Tới chân núi Thần Quật, đoàn người chạm mặt ba Thái Cổ di chủng cầm đầu là Hoàng Kim sư tử chín đầu, người khổng lồ Ngân Huyết và Vũ Vương, cùng đám thiên tài Nhân tộc đã bị hàng phục làm tôi tớ. Cả ba tranh nhau muốn thu nhóc tỳ làm chiến sủng, nhưng nó ngạo mạn từ chối và tuyên bố ngược lại muốn bắt chúng làm tôi tớ. Trong đại chiến một chọi ba, nhóc tỳ đấm Ngân Huyết chảy máu tay, đá Vũ Vương văng ra hộc máu, rồi dùng bảo cốt Toan Nghê thi triển 'Nghịch chuyển' phản đòn Sư Tử chín đầu, đánh lui hai kẻ và ngang sức với sư tử khiến cả trường kinh hãi. Nhóc tỳ điềm nhiên thừa nhận đã ăn thịt Mộc Phong của Linh tộc, tuyên bố mục đích vào Bách Đoạn sơn là hàng phục cho bằng được một Thái cổ hung thú non như con của Chân Hống hay hậu duệ Kim Sí Đại Bằng. Hoàng Kim sư tử chặn ải, chín đầu phun chín phi kiếm hoàng kim, còn Hỏa Linh Nhi vừa bị nhóc tỳ trêu vừa sốt ruột giục sư tử mau thu phục kẻ ngông cuồng này."},{"chuong":122,"tieuDe":"Đánh Bại Sư Tử Chín Đầu","tomTat":"Trời về chiều, trên thảo nguyên mênh mông của Đại hoang, Nhóc tỳ đại chiến Hoàng Kim sư tử (Sư Tử chín đầu) tuy cảnh giới thấp hơn vẫn đánh ngang tài, khiến Dị tộc và người xem kinh hãi. Sư tử tung Sư Hống công, chín răng nanh phi kiếm do trưởng bối tặng và chuỗi niệm châu vàng, nhưng bị Cốt Tiễn (Kim Giao tiễn) của Nhóc tỳ làm một đầu lâu suýt nứt, trọng thương; sau cú va chạm Thần Huy cả hai đều phun máu, đây là lần đầu Nhóc tỳ bị thương kể từ khi vào Tiểu Thế Giới. Sư tử liền tung thần thông trấn tộc Vô Úy Sư Tử ấn khiến thiên tài Bổ Thiên các trắng bệch mặt, nhưng Nhóc tỳ vận Nguyên Thủy Chân Giải cùng Chiến Thần Đồ Lục, biến hóa Phù Văn mấy chục lần mà hóa giải. Ngộ ra chiến đấu đỉnh cấp không cần đại thần thông, Nhóc tỳ chỉ tổ hợp Phù Văn thường cũng phá tan chiêu này. Hoàng Kim sư tử tiêu hao quá nhiều tinh khí thần nên bỏ chạy, bị Nhóc tỳ nhảy lên cưỡi và dùng sấm sét trấn áp. Cuối cùng Nhóc tỳ do dự giữa việc làm thịt hay giữ Sư Tử chín đầu — vốn thuộc mười tọa kỵ hàng đầu thời Thượng cổ — làm thú cưỡi, khiến các sinh linh chứng kiến khiếp sợ vì quá hung tàn."},{"chuong":123,"tieuDe":"Thần Quật","tomTat":"Sư Tử chín đầu huyết thống cao quý phẫn nộ chống trả nhóc tỳ đang cưỡi trấn áp nó, tung chín hạt niệm châu và răng nanh hóa phi kiếm, nhưng nhóc tỳ hóa thân sấm sét chống ngang lực rồi dùng Cốt Tiễn hóa giao long chém rụng bốn đầu lâu, khiến Sư Tử bại trận bỏ trốn vào một lỗ đen giữa sườn núi được gọi là Thần Quật. Nhóc tỳ từ chối vào theo vì cảm giác nơi này quỷ dị, để Hỏa Linh Nhi dẫn đoàn thiên tài Nhân tộc cùng Ngân Huyết và Vũ Vương tiến vào; nó cùng các sư huynh sư tỷ Bổ Thiên các ở lại, hầm bốn đầu lâu chứa thần tính với linh dược thành lò bảo dược cùng ăn. Năm thiên tài Bổ Thiên các nhờ đó lần lượt đột phá, riêng nhóc tỳ ăn phần lớn nhưng từ chối đột phá ngay để hòa tinh khí thần tạo cơ sở vững, do vừa mượn Tử Vân Tâm mở ra Động Thiên thứ bảy. Nửa đêm bầy sói dị chủng có tổ chức cùng mấy chục Lang Vương vây công, khiến các thế lực bên trong nhận ra đây thực là Ma Quật — vùng đất trầm tịch của Lang Thần nuôi sói. Sáng ra các đoàn thoát ra đầy thương vong, Hỏa Linh Nhi đoạt được một quả trứng vàng nghi là hậu duệ Lang Thần khớp với chữ khắc trên vách. Khi trứng rơi ra giữa cuộc tranh cướp hỗn loạn, nhóc tỳ vọt tới ôm chặt đòi luộc ăn rồi xông qua bầy sói biến mất, để cả đám kêu thảm truy đuổi."},{"chuong":124,"tieuDe":"Nướng Ra Một Thần Linh","tomTat":"Nhóc tỳ Thạch Hạo cướp được trứng thần màu vàng và ôm chạy, bị cả đám người truy đuổi nhờ mùi U Lan Thảo vẩy lên trứng. Đại thảo nguyên bạo động ban đêm, vô số cự lang cùng mấy chục Lang Vương hiểu Bảo Thuật quần công; nhóc tỳ dùng Cốt Tiễn màu vàng phá vòng vây, đạp bảo kính Toan Nghê bay cao rồi nhảy xuống sông lớn cắt mùi trốn thoát. Nó suy đoán trứng có thể là hậu duệ Thần linh sánh vai hung thú Thái Cổ, nhắc mục đích lớn nhất khi vào Tiểu Thế Giới là bắt một hung thú Thái Cổ non về Thạch thôn, và tiết lộ mặt trời của thế giới này thực chất là thi thể Thái Cổ Kim Ô. Cho rằng trứng đã hư, nhóc tỳ nhóm lửa nồi sắt quyết định nướng/luộc để lấy vật chất thần tính. Đoàn Hỏa Linh Nhi, Ngân Huyết cự nhân, Vũ Vương chạy vòng cả đêm rồi quay về điểm xuất phát, tức đến hộc máu, nhờ U Lan Thảo tìm ra nhóc tỳ và xông vào đại chiến; năm vị thiên tài Bổ Thiên các ra tay giúp nó. Trong lúc nhóc tỳ dùng trứng làm lá chắn, lửa và tia điện đập vào khiến vỏ nứt vỡ, cuối cùng một thần linh non thực sự nở ra, cuộn tròn trong lòng bàn tay."},{"chuong":125,"tieuDe":"Ấu Thần","tomTat":"Một sinh linh nhỏ bé bọc trong ánh sáng ngũ sắc ra đời giữa vòng vây tranh đoạt, hấp thu sạch mọi bảo thuật, mưa sáng và tia điện để trưởng thành, lộ hình sói con lông xám có sừng nhú cùng đôi cánh nhỏ — hậu đại của Lang Thần và được nhận ra là một Ấu Thần. Nhóc tỳ Nhân tộc bọc lấy nó xông ra, dùng chớp và Cốt Tiễn vàng kim đánh cháy tay người khổng lồ Ngân Huyết, chặt gãy hung đao và đứt một cánh tay Vũ Vương, buộc đám truy đuổi rút lui. Dùng Tham Cốt pháp trong Nguyên Thủy Chân Giải thăm dò sói con nhưng chỉ thấy máu huyết mạnh mà không có phù cốt hay ấn ký, nhóc tỳ hoãn lại đợi cảnh giới cao hơn. Sói con quyến luyến bám vai nhóc tỳ, được Hỏa Linh Nhi cho ăn Linh dược và trái tim hung thú, còn nhóc tỳ hỏi 'có sữa không' khiến nàng nổi giận đuổi đánh suốt hai giờ, lộ biệt danh cũ 'Thích Uống Sữa Thú Nhất' ở Hư Thần Giới. Ngân Huyết và Vũ Vương bị truy sát bắt trói, còn Sư Tử chín đầu — cháu Cửu Linh Vương, thuần huyết từng giết thần — bị nhóc tỳ đại chiến rồi thu phục làm thú cưỡi kiêm tiểu đệ, bị ép đòi đại lễ Linh dược, Thánh dược và giúp tìm Bất Lão Thần Tuyền. Sư Tử chín đầu phát thệ khuất phục sau khi nhận ra sói con chính là Ấu Thần. Ở nơi khác, Vũ tộc tụ tập dưới mưa hấp thu sức mạnh, tra khảo Độc Giác Nhân Hùng và quyết mai phục chờ thiếu niên hung tàn xuất hiện."},{"chuong":126,"tieuDe":"Vũ Tộc","tomTat":"Thạch Hạo cưỡi Sư Tử chín đầu — di chủng Vương tộc Thái Cổ có thuần huyết đã bị hắn hàng phục làm tọa kỵ — xông qua núi rừng khiến vạn thú tránh né, rồi chia tay công chúa Hỏa quốc và các thiên tài Bổ Thiên các để đi tìm Bất Lão Thần Tuyền. Thạch Hạo đòi mượn xem chuỗi niệm châu vàng và kim kiếm của Sư Tử nhưng bị kiên quyết từ chối, hai bên tranh cãi uy hiếp qua lại, Sư Tử dọa tự bạo. Phát hiện cường giả Nhân tộc mai phục ở thông đạo, Thạch Hạo nghi có bộ tộc muốn luyện Cửu Chuyển Linh Đan cần sáu giọt bảo huyết Thái Cổ nên nhắm bắt Sư Tử. Đổi hướng sang vùng ngập nước sương mù, hai người sa vào năm tầng sát trận Phù Văn cổ, dùng Kim Giao tiễn và chuỗi niệm châu phá trận, cuối cùng thoát ra với vài vết thương nhẹ. Mười thiếu niên cường giả Vũ tộc tới, kinh sợ khi nhận ra người hàng phục được Sư Tử chín đầu, rồi hiện bảo quang trong mưa. Một người kể chuyện tám năm trước bộ tộc điều cao thủ đánh vợ chồng Thạch Tử Lăng máu nhuộm Tây Cương để thăm dò thân phận Thạch Hạo, hé lộ ân oán mẫu thân Thạch Nghị (Vũ tộc) đã trộm Chí Tôn cốt của Thạch Hạo đưa vào con trai. Thạch Hạo lạnh lùng không đáp, chỉ vung bảo kính trong tay ra tay phản kích."},{"chuong":127,"tieuDe":"Săn Bắn Trong Mưa","tomTat":"Trong tiểu thế giới ao hồ đầm lầy mưa giăng, mười thiên tài Vũ tộc phát hiện bảo cụ trên tay nhóc tỳ liền hợp lực thi triển các Bảo Thuật thủy hệ như Tà phong tế vũ Trảm tinh nguyệt và Thông thiên động địa, uy lực ngang hai ba mươi người, đè ép cả một vùng núi. Nhóc tỳ cùng Sư Tử chín đầu phản kích bằng lôi đình từ bảo cốt Toan Nghê chuyên khắc chế Vũ tộc, nước dẫn điện khiến cả nhóm cháy đen thành tro. Trước khi chết, kẻ sống sót nhận ra cậu chính là đứa trẻ mất Chí Tôn cốt hơn tám năm trước và tiên đoán một đại sát kiếp, rồi cũng bị bắn nổ tung. Nhóc tỳ tiếp tục truy sát khắp vùng đầm lầy, giết tổng cộng hai mươi thiên tài Vũ tộc, sinh nghi vì số lượng địch đông bất thường và cảnh giác né tránh một con Ngư Long trong hồ. Ở con đường khác, song kiệt Vũ tộc canh giữ thông đạo bàn về Thạch Nghị đang xông Thượng Cổ cấm địa tìm Thiên Cốt cùng khả năng Trùng Đồng, khi một cường giả cháy đen chạy tới báo tin người của họ đã bị giết sạch. Nhóc tỳ cưỡi Sư Tử chín đầu như thần nhân hạ giới, đánh gục thêm mười tám thiên tài rồi dùng bảo kính Toan Nghê giết chết kẻ truyền tin ngay trước mặt bọn Vũ tộc. Cuối cùng, một thiếu nữ chừng mười lăm mười sáu tuổi thuộc song kiệt Vũ tộc đứng dậy trước thông đạo, Phù Văn lấp lóe đầy trời, hé mở trận đối đầu sắp tới."},{"chuong":128,"tieuDe":"Thông Linh","tomTat":"Vũ Tử Mạch, thiếu nữ tà áo xanh của Vũ tộc và là một trong 'song kiệt' cùng Thạch Nghị, sở hữu Thông Linh Thần Giác nhưng không thể nhìn thấu nhóc tỳ vì bị sương mù bao phủ, giống hệt trường hợp Thạch Nghị. Phụng lệnh trưởng bối vào Bách Đoạn sơn truy giết kẻ đã hạ mười tám cao thủ Vũ tộc, nàng thi triển Bảo Thuật Thông Linh 'Nhất Thế Họa Quyển', dùng ký tự dệt sách cổ Phù Văn gần như bất hủ để phong ấn đối thủ. Nhóc tỳ ngồi trên Sư Tử chín đầu phản kích bằng cối xay bạc phá vỡ quyển sách cổ, khiến bảo thuật của nàng mất hiệu lực. Vũ Tử Mạch chuyển sang hóa mưa thành binh và triển khai 'Trong mưa sinh điện', tia chớp xanh đánh nát một tòa núi nhỏ thành bốn mảnh. Tuy nhiên nhóc tỳ tinh thông lôi điện, dùng bảo kính Toan Nghê khắc chế công pháp Vũ tộc, đánh nàng ho ra máu và lần lượt hủy Bảo Tán, Bảo Y lông chim tím của nàng. Cùng đường, Vũ Tử Mạch tái triển Thông Linh dệt bức tranh nhiều màu phòng ngự, Phù Văn tạm chặn được lôi đình thần uy. Nhóc tỳ liền buông lời khiêu khích thân hình khiến nàng nổi giận run bần bật, Phù Văn lay động bất ổn, rồi thúc giục Toan Nghê phóng lôi đình cùng điện vàng đánh thẳng tới."},{"chuong":129,"tieuDe":"Người Phong Ấn","tomTat":"Nhóc tỳ ở Hư Thần giới điên cuồng oanh kích Vũ Tử Mạch, đánh tan Phù Văn cuối cùng và làm gãy hai cánh tay nàng khiến đòn cuối bảo thuật Thông Linh thất bại, buộc thiếu nữ thiên tài Vũ tộc phun máu bại trận; nàng kinh hãi nhận ra thân thể cuồng bạo của nhóc tỳ giống với Thạch Nghị vài năm trước. Ngay khi nhóc tỳ chuẩn bị đòn giết cuối, bốn siêu cấp cường giả Vũ tộc xuất hiện ở bốn hướng vây bắt nó cùng Sư Tử chín đầu; qua bàn tay đầy nếp nhăn, nhóc tỳ vạch trần chúng là Người phong ấn — kẻ tự phong ấn thực lực để vượt cấm chế tuổi tác của Bách Đoạn sơn, tiểu thế giới bài xích người quá mạnh. Hai bên giả liều mạng rồi bất ngờ dùng Bảo Cụ dưới chân phóng lên trời bỏ chạy, nhóc tỳ biến Sư Tử chín đầu thành khiên thịt che sau, cả bọn vừa trốn vừa chiến đều bị thương nặng. Sư Tử chín đầu bị màn mưa thần lực bắn thủng ngực phải như cái sàng, nhóc tỳ cũng ho ra máu nhưng nhờ thân thể sánh Thiên giai Thái Cổ hung thú con nên trụ được. Trong tuyệt cảnh, nhóc tỳ quát 'Đi!' chủ động chặn bốn đại cường giả để mở đường sống cho Sư Tử chín đầu, khiến nó cảm động hứa xóa món nợ cũ với Cửu Linh Vương rồi phóng hào quang hoàng kim biến mất cuối chân trời. Bốn cường giả thu mưa lộ chân thân gồm hai lão già và hai trung niên, nhận ra chân mày lúc nhóc tỳ nổi giận giống hệt Thạch Tử Lăng năm xưa và gọi nó là 'tiểu nghiệt súc năm đó'. Trung niên Vũ Côn lộ danh tính, kể lại thúc tổ mình từng đuổi Thạch Tử Lăng từ Hoàng Đô tới Tây Cương, dùng Cốt Tiễn xuyên thủng lá phổi suýt trúng tim, rồi chằm chằm muốn nhìn rõ mặt nhóc tỳ."},{"chuong":130,"tieuDe":"Vô Đề","tomTat":"Bốn cường giả Vũ tộc quyết truy sát nhóc tỳ vì nghi ngờ nó chính là đứa bé sắp chết năm xưa, kẻ dù mất Chí Tôn Cốt vẫn quật khởi với thiên tư đáng sợ, nên muốn tốc chiến diệt trừ trước khi Võ Vương phủ hay biết. Nhóc tỳ dùng cây quạt bạc phù cốt nạp lực sấm sét từ bảo kính Toan Nghê rồi ném nổ tung phản kích, tuy không giết được ai nhưng thoát thân dù thân thể đầy thương tích lộ cả xương. Nó cố ý giả ngã bên bờ hồ lớn, giấu bảo kính nhắm mặt nước, chờ bốn kẻ địch xông tới liền oanh tia sấm chớp khuấy động hồ, dụ con Ngư Long khổng lồ trồi lên nuốt chết một cường giả và cắn tàn phế một kẻ khác. Hai kẻ còn lại vác đồng bọn mất hai chân bỏ chạy rồi điều động Bảo Cụ tiếp tục truy sát, không dám liều với Ngư Long vì sợ pháp tắc tiểu thế giới. Trên đường trốn, nhóc tỳ suýt đụng Hỏa Vân Tước Đại Hồng — con ác điểu từng bị nó 'mượn' hai mươi cân thịt nên khiếp sợ gọi nó là Ma Vương; nó đánh gục và ôm chặt cổ Đại Hồng để cưỡi thoát thân. Đại Hồng định phản kháng bay ngược về phía truy binh mong có người thu phục Ma Vương, nhưng bị nhóc tỳ dọa 'xin thịt' liền rụt cổ quay đầu hóa áng lửa xẹt qua tầng mây. Hai cao thủ Vũ tộc sắp đuổi kịp thì con mồi bỗng biến thành kỵ sĩ chim bay mất, tức đến đau khắp người."},{"chuong":131,"tieuDe":"Lông Chim Mù Trời","tomTat":"Vũ Côn và Vũ Văn đuổi theo Thạch Hạo đến kiệt sức nhưng nó cưỡi Đại Hồng Điểu (Hỏa Vân Tước) bay mất trong sương mù, đành từ bỏ và quyết giết nhóc tỳ khi có cơ hội. Thạch Hạo khống chế Đại Hồng Điểu làm phương tiện bằng cách dọa ăn thịt, gõ đầu và vặt lông, buộc nó dẫn đến sào huyệt Tọa Sơn Điêu — nơi có tổ chim khổng lồ với gò xương hài cốt nhân loại và ba quả trứng lớn lót trong Ngân Lũ Thảo. Đại Hồng Điểu cắt trứng bằng lông vũ rồi phun lửa nướng chín; Thạch Hạo ăn cả ba quả, vận chuyển phù văn luyện hóa tinh khí thần chữa lành toàn bộ vết thương, thể phách mạnh hơn và tròng mắt trong suốt hơn. Khi Tọa Sơn Điêu về tổ điên cuồng công kích, Đại Hồng Điểu phản kích và đánh đuổi được đối thủ nhưng bị thương thảm hại. Mặt khác, Vũ tộc truy tìm Thái Nhất Chân Thủy — thần dịch trân quý một giọt giá trị liên thành, có thể khiến tộc quật khởi và xuất hiện Nhân Hoàng — Vũ Côn xác định ao nước trước mặt chính là hồ Thái Nhất Chân Thủy nhưng nơi này xuất hiện ảo cảnh vừa lừa dối vừa kêu gọi tiến gần, hai ngày qua Vũ tộc không thể tiếp cận."},{"chuong":132,"tieuDe":"Tài Cao Chót Vót","tomTat":"Đại Hồng Điểu bay nhiều ngày mệt rũ đòi bãi công, bị Thạch Hạo nhổ lông rồi dùng Cốt Tiễn vàng kim hiện bản thể đầu rồng cắn cổ chảy máu ép tiếp tục truy tìm Vũ tộc. Thạch Hạo lấy lông thần Tiểu Hồng Điểu tỏa thần uy Chí Tôn khiến Đại Hồng Điểu run sợ, lật mặt quỳ xin làm đồ đệ, rồi hăng hái tìm được tin Vũ tộc đã vào sa mạc tìm chí bảo. Hai bên tiến vào sa mạc vàng kim, phát hiện bảo dược Sa Mạc Ngân nhưng thiếu niên áo bạc Tiêu Thiên đã hái trước và chém chết mấy con bò cạp bạc. Khi bò cạp bạc ẩn trong cát chui ra phục kích, Thạch Hạo dùng Cốt Tiễn cứu Tiêu Thiên, đồng lúc Tiêu Thiên đột phá mở được Động Thiên thứ tám. Qua chuyện cùng ghét bốn chữ tài cao chót vót, Tiêu Thiên xem Thạch Hạo là tri kỷ mà không biết đây chính là kẻ từng đánh trộm mình. Tiêu Thiên tiết lộ mục tiêu Thánh Vật Thái Nhất Chân Thủy và thổ lộ căm ghét đại địch đầu gấu vạn ác — chính là Thạch Hạo đang giả vờ kết giao bên cạnh; hai người quàng vai đồng hành lặng lẽ đi sâu vào sa mạc."},{"chuong":133,"tieuDe":"Thái Nhất Chân Thủy","tomTat":"Trong một mảnh sa mạc nóng như lò lửa của Bách Đoạn sơn, Vũ tộc tiến gần Thần trì chứa Thái Nhất Chân Thủy — dị bảo vô giá đã thông linh, diễn hóa phù văn pháp tắc và triệu hoán hơn mười bộ hài cốt cường giả để chống lại. Vũ Văn Thành, Vũ Côn dùng nước Hoàng Tuyền phá tan toàn bộ hài cốt, nhưng một gốc linh đằng thủ hộ trồi ra hủy vỡ túi càn khôn phỏng chế của Vũ Côn khiến lão phun máu gãy xương bại trận. Vũ tộc lập tế đàn, đốt giấy vàng hiện pháp chỉ truyền miệng của Vũ thần cùng di vật tổ tiên để chứng thực là hậu duệ, khiến nước thần nguyện đi theo. Nhóc Tỳ, Đại Hồng Điểu và Tiêu Thiên ẩn nấp quan sát; Tiêu Thiên tiếc nuối vì Vũ tộc đến trước, giải thích về túi càn khôn Thượng Cổ. Khi Vũ tộc trang trọng thu Thái Nhất Chân Thủy vào đỉnh ngọc mơ tưởng lập quốc, Nhóc Tỳ tự nguyện xông vào, mượn lực bật từ quy thuẫn của Tiêu Thiên vọt ngang như sao băng. Sức bật kinh khủng đánh bay Tiêu Thiên năm sáu dặm làm quy thuẫn vỡ vụn, còn Nhóc Tỳ nhào vào Bảo Cụ đỉnh ngọc quẫy nước rầm rầm và nuốt từng ngụm lớn Thái Nhất Chân Thủy, khiến Vũ tộc choáng váng đông cứng ngỡ là ảo giác."},{"chuong":134,"tieuDe":"Uống Sạch","tomTat":"Nhóc Tỳ từ trên trời đập xuống ngay giữa Thái Nhất Chân Thủy của Vũ tộc, vùng vẫy trong nước thần mà uống thẳng vào bụng, phá tan kế hoạch luyện bảo cụ của bộ tộc. Vũ tộc chia hai phe — kẻ muốn giết ngay, kẻ muốn cướp phần chân thủy trước — trong khi Nhóc Tỳ dùng Định Quang Châu tạo màn sáng hình cầu ngăn phù văn và tạm giữ nước thần, khiến Vũ Văn Thành nhận ra đó là mảnh vỡ thời thượng cổ. Thái Nhất Chân Thủy có linh, thành tinh chui ra từ thất khiếu và lỗ chân lông, buộc Nhóc Tỳ vận Nguyên Thủy Chân Giải bịt kín để tiếp tục uống. Khi Định Quang Châu mờ dần, Nhóc Tỳ đổ đầy một bình ngọc, bỏ Định Quang Châu vào rồi dùng Cốt Tiễn cắt đứt đỉnh ngọc; phần chân thủy còn lại hóa sương mù vàng trốn vào lòng đất cùng linh đằng. Đại Hồng Điểu bay đến đón Nhóc Tỳ khỏi vòng vây, Nhóc Tỳ nhổ lông lấy máu chim vẽ lên mặt che giấu mặt thật. Ba người hội quân, chạy vào núi nguyên thủy đáp xuống một ngọn Linh sơn, Tiêu Thiên kích động ôm bình ngọc còn Nhóc Tỳ ngồi luyện hóa nhưng nước thần cứ phun ra đằng miệng."},{"chuong":135,"tieuDe":"Khí Tức Của Chí Tôn","tomTat":"Trên Linh sơn, Nhóc Tỳ ngồi xếp bằng cố luyện hóa Thái Nhất Chân Thủy, cả người phát sáng dù đã bịt kín lỗ chân lông. Đại Hồng Điểu tiếc rẻ thánh vật bị phung phí nên phun ra một nồi đen (trứng chim mài giũa) có phù văn lôi điện để hấp thu nước thần, còn Tiêu Thiên cảnh báo uống nhiều sẽ bị nước thần luyện hóa ngược. Thái Nhất Chân Thủy có linh tính liền tụ lại phản luyện hóa, trùng kích mãnh liệt khiến xương cốt Nhóc Tỳ rung răng rắc, suýt nổ tan xác nhưng nhờ thân thể sánh con non hung thú Thái Cổ thiên giai mới trụ được. Đúng lúc nguy cấp, ngực nó nóng bừng hào quang, thiên địa thất sắc, nước thần bị ép thành mặt trời nhỏ chứa hình vị Chí Tôn thai nghén — mầm Chí Tôn Cốt mới hình thành. Nhóc Tỳ nhận ra khí tức Chí Tôn Cốt quen thuộc từ bé; chương hé lộ nó vốn là con cháu dòng chính Võ Vương phủ, bảo cốt và tinh huyết cũ bị cướp đoạt đã bắt rễ trong Thạch Nghị. Sau khi nước thần được hấp thu hoàn toàn, Nhóc Tỳ đột phá khai mở Động Thiên thứ tám không dấu hiệu báo trước, khiến Tiêu Thiên và Đại Hồng Điểu bàn luận về khả năng mở cả Động Thiên thứ chín truyền thuyết."},{"chuong":136,"tieuDe":"Đồng Lõa","tomTat":"Sau khi được Thái Nhất Chân Thủy tẩy lễ, thân thể Nhóc Tỳ tăng cường một bậc: ngũ tạng vang như trống trời, cốt cách trong suốt như ngọc. Nó thị uy sức lực bằng cách nhảy từ đỉnh núi làm vỡ hố sâu và một tay nhấc tảng đá ba bốn chục vạn cân, khiến Tiêu Thiên và Đại Hồng Điểu kinh sợ. Tiêu Thiên cảm thấy Nhóc Tỳ giống thằng nhỏ đầu gấu ở Hư Thần Giới nhưng tự trấn an vì nghĩ nếu đúng thì nó đã cướp nước thần chạy mất. Nhóc Tỳ định cùng Đại Hồng Điểu cướp Thái Nhất Chân Thủy của Tiêu Thiên, nhưng khi động thủ lại quay sang đập cục đá vào ót Đại Hồng Điểu rồi đổ tội cho nó định đánh lén. Tiêu Thiên tin lời, trách Đại Hồng Điểu; Đại Hồng Điểu uất ức hộc máu nhưng vì cần được giới thiệu sư phụ nên không dám vạch mặt. Cuối cùng Tiêu Thiên và Nhóc Tỳ chia chác nước thần, gạt Đại Hồng Điểu ra ngoài rồi khích nó bằng lối chơi chữ, khiến nó đành bụm lỗ mũi chở hai người bay đi tìm Vũ tộc."},{"chuong":137,"tieuDe":"Chương 137: Đại Thắng","tomTat":"Đại Hồng Điểu bay ngang dãy núi bị Bạo Viên cùng hung thú bắt nạt, phải hóa lửa bỏ chạy dù tự xưng đời sau thần điểu Chu Tước. Nhóc Tỳ cùng Tiêu Thiên và Đại Hồng Điểu vào sa mạc tìm Vũ tộc và Thái Nhất Chân Thủy, phát hiện Vũ Văn Thiên đã tàn phế đang chờ Thạch Nghị tới dùng Song đồng phá hư không. Nhóc Tỳ chủ động xuất hiện, dùng thần lực thiên phú kết hợp phù văn đánh Vũ Văn Thiên phun máu gãy cánh tay, rồi dùng bảo kính Toan Nghê và Cốt Tiễn màu vàng phá và cắt đứt sừng thú đen. Tiêu Thiên vây chặn còn Đại Hồng Điểu mang nồi đen tàn sát đám đệ tử Vũ tộc. Vũ Văn Thiên ngồi Linh Vũ định trốn thì bị Cốt Tiễn kẹp đứt rồi bị Nhóc Tỳ chém rụng đầu, chết trong uất ức. Toàn bộ Vũ tộc tiến vào Bách Đoạn sơn bị diệt sạch, chỉ còn Vũ Côn, Vũ Văn Thành và Vũ Tử Mạch sống sót. Sau chiến thắng Nhóc Tỳ qua thông đạo màu vàng vào thiên địa mới, bị người Võ Vương phủ đang săn di chủng quát đuổi và giật mình nhận ra đây chính là nơi mình ra đời nhưng năm xưa đã bị bỏ rơi."},{"chuong":138,"tieuDe":"Con Cháu Võ Vương Phủ","tomTat":"Một con Tử Điêu Thái Cổ di chủng tím óng dài một trượng, trán có mắt dọc, đang bị trọng thương thì bị nhóm thiếu niên Võ Vương phủ vây bắt. Nhóc Tỳ nhảy xuống ngăn cản, hồi tưởng việc mình mất Chí Tôn cốt và tám năm bị bỏ rơi chỉ còn a Man làm bạn, rồi động thủ vỗ tan phù văn, đánh tan giao long và vuốt giao, tay không đoạt tấm da giao thú và quần công cả đám thành đầu heo. Nhóc Tỳ chất họ thành đống ngồi lên hỏi “đã phục chưa”, Đại Hồng Điểu nhảy nhót cầm nồi đen đập làm nhục, đám thiếu niên xấu hổ rút lui đi tìm Tứ ca, Lục ca, Cửu đệ và Thạch Nghị đường đệ trong cấm địa. Con Tử Điêu biết ơn tiết lộ có một khu di tích chứa đầy bảo cụ thông linh như Kiếm sơn, sừng thú, Thần hoàn, và kể mình trốn ra từ một cấm địa quý giá nhất Bách Đoạn sơn. Cả nhóm cùng nhau xuyên qua thông đạo màu vàng, vượt hai mươi bốn khu vực đầy trận chiến để tiến vào trung tâm hoang vu như ma thổ, nơi vô số sinh linh cường đại của các gia tộc cổ, Tịnh thổ và Vương tộc Cổ quốc đang do dự trước cửa di tích."},{"chuong":139,"tieuDe":"Chương 139","tomTat":"Trước một sơn môn tráng lệ tụ tập vô số Thái Cổ di chủng huyền thoại: Thổ Hành Long dài năm mươi mét, Bạo Viên đen, Liệt Thiên Ma điệp có thể nứt vỡ vạn dặm trời xanh, bầy Kiến Thần mười hai con, Bồ Ma thụ hút thần tinh, và Tất Phương Ma cầm Thiên giai từng ăn thịt Thần linh. Nhóc Tỳ hoành hành giữa đám di chủng, đẩy cường giả sang hai bên, một cước đánh gãy xương hàm một hung thú khiến cả đám hoảng sợ. Gặp lại Sư Tử chín đầu (Hoàng Kim sư tử, hậu đại Thái Cổ Thần vương), Nhóc Tỳ tiết lộ đã giết hai trong bốn lão già truy sát trước đó và ép nó nhận làm tiểu đệ giữa đông đảo di chủng khiến nó mất mặt. Hai cường giả Tộc ba mắt anh em ruột và chim Loan năm màu xuất hiện; chim Loan trêu chọc chín đầu và đòi làm thịt thiếu niên Nhân tộc. Nhóc Tỳ tiến lên chỉ mặt cả hai cường giả bảo tránh ra, dọa chim Loan chọn nướng hoặc luộc, không thèm để ai vào mắt, khiến cả sơn môn náo động ầm ĩ."},{"chuong":140,"tieuDe":"Giương Cao Hung Uy Của Nhân Tộc","tomTat":"Nhóc Tỳ đối đầu chim Loan năm màu (hậu duệ Thần điểu), coi nó chỉ là món ăn; chim Loan bắn lông vũ hóa mũi tên nhưng bị Sư Tử chín đầu chặn lại vì tổ phụ chim Loan có giao tình với Cửu Linh Vương. Các di chủng vây lại: hai huynh đệ Tộc ba mắt chế nhạo, Phì Di (Thái Cổ di chủng cựu thù từ Đoạn Không thành) và Quạ Lửa cùng góp mặt ngoài sơn môn nguy nga. Nhóc Tỳ sai Đại Hồng rửa nồi đen đun nước sôi mở tiệc hầm di chủng, rồi đánh bại hai huynh đệ Tộc ba mắt bằng cách nắm mắt cá chân nện xuống đất và dùng tù binh chắn đòn phản kích. Trong đại chiến, Nhóc Tỳ vận toàn bộ bảo cụ: bảo kính Toan Nghê phóng sấm sét, đối phó Bảo Phiến năm màu của chim Loan và phi kiếm răng nanh Hỏa đạo của Phì Di. Nó dùng Thần nguyệt cùng bảo kính áp chế, đoạt phi kiếm đỏ của Phì Di, phát Long Giao tiễn suýt cắt đôi rồi bảo kính sấm sét đánh gục Phì Di. Cốt Tiễn màu vàng chặt đứt hơn mười cân huyết nhục cẳng chân và đục lỗ cánh thần chim Loan; bốn đại cường giả đều thất bại trong thời gian ngắn. Nhóc Tỳ lấy thịt chim Loan, xách Phì Di lên vai làm tiệc, mời Sư Tử chín đầu; khi rửa mặt bên suối, thân phận nhóc siêu quậy ở Hư Thần giới bị lộ khiến các thiên tài Toan Nghê, Li Long, Tỳ Hưu, Tất Phương khiếp sợ mà không dám động thủ."},{"chuong":141,"tieuDe":"Ăn Như Gió Cuốn","tomTat":"Nhóc Tỳ tiến vào tiểu thế giới Bách Đoạn sơn, lập tức gây chấn động thiên tài các tộc bởi cái danh nhóc siêu quậy từ Hư Thần giới mà nhiều thế lực từng treo giải lấy đầu. Bên dòng suối cạnh sơn môn, Đại Hồng Điểu hầm canh rắn Phì Di còn Nhóc Tỳ nướng thịt chim Loan năm màu, ăn ngấu nghiến trước mặt cả đám Thái Cổ di chủng thèm thuồng mà tức tối; nó cùng Tử Điêu và Đại Hồng Điểu nuốt túi mật rắn để bồi bổ đột phá. Nhờ mật Thái Cổ di xà và hơn nửa con Phì Di, Đại Hồng Điểu tắm lửa thăng cấp, thực lực tăng vọt, còn Tử Điêu lành thương suýt đột phá; riêng Nhóc Tỳ dù được gột rửa thân thể vẫn chưa mở nổi Động Thiên thứ chín. Sư Tử chín đầu khó xử không dám ăn vì chim Loan là họ hàng nhiều đời, còn chim Loan tức giận bay lượn trên trời nhưng không dám lao xuống quyết chiến. Ăn no, Nhóc Tỳ trị thương và kết giao với các di chủng quen biết Sư Tử chín đầu, đồng thời không hay biết bốn đại cường tộc từng bị nó làm nhục ở Hư Thần giới đã cử người tới báo thù, có kẻ muốn bắt sống nó để đoạt lại bảo phiến Xích Vũ. Bất chấp lời cảnh báo về bảo cụ thông linh tự chém giết người tiếp cận, Nhóc Tỳ kêu gọi cả đoàn xông vào Thượng Cổ phế tích săn bảo. Nhiều sinh linh khủng bố như Tất Phương, Tỳ Hưu, Li Long cũng đồng loạt tiến vào, báo hiệu sát kiếp sắp nổi."},{"chuong":142,"tieuDe":"Thần Triều","tomTat":"Nhóc Tỳ dẫn đoàn Thái Cổ di chủng tiến vào khu phế tích Thượng Cổ trong Bách Đoạn sơn, nơi cất giấu vô số bảo cụ thông linh biết di chuyển. Bị một Người phong ấn áo bào xanh của một trong bốn đại gia tộc từng bị nó vơ vét chém lén, Nhóc Tỳ dùng bảo kính Toan Nghê đánh nứt xương bả vai đối phương, buộc hắn phải dùng Súc Địa phù trốn thoát. Trong hai ngày, nó trở thành cường hào càn quét phế tích, truy sát ngược lại các cường giả Nhân tộc âm mưu hại mình. Bất ngờ Thần triều nổi lên: vô số bảo cụ Thái Cổ thức tỉnh tàn sát điên cuồng, giết hơn hai ngàn thiên tài, khiến Nhóc Tỳ đành bỏ chạy dù thấy nhiều dị bảo quý giá. Sống sót và tách khỏi nhóm, nó đi sâu vào phế tích, tìm ra quy luật Thần triều và ngọn nguồn ở vùng núi bên trong. Sau khi thoát khỏi một cuộc phục kích của năm Người phong ấn bằng cách dẫm sụp cả ngọn núi, Nhóc Tỳ phát hiện một cốt tháp thần thánh trắng toát và ra tay trấn áp để đoạt lấy. Đúng lúc đó, một con Bạch Hổ ngồi trên xe kéo bảo cụ kéo tới, nhận ra nó từ Đoạn Không thành và tuyên bố cốt tháp đã thuộc về mình."},{"chuong":143,"tieuDe":"Chí Bảo Trong Di Tích","tomTat":"Nhóc Tỳ tranh đoạt tòa cốt tháp trắng tinh lơ lửng trong khe núi di tích thì bị con Bạch Hổ Thái Cổ di chủng biết nói tiếng người dẫn lão già cùng đám thủ hạ tới quấy phá và ra lệnh giết hắn. Bị quấy nhiễu nhiều lần, cốt tháp thức tỉnh thành tinh, bùng nổ ánh sáng như sao băng hủy diệt cả vùng núi, bắn xuyên vai Bạch Hổ và ngực lão già khiến chúng tháo chạy, rồi tự hóa cầu vồng lao vào biển lửa Địa Hoàng Hỏa để tế luyện lột xác. Nhóc Tỳ cưỡi bảo kính Toan Nghê đuổi theo, đồng thời để mắt thèm muốn chiếc túi Càn Khôn làm từ da Thái Cổ di chủng có thể chứa vạn vật. Chưa kịp lấy tháp, hắn bị thanh niên áo bào xanh dẫn gần hai mươi người Côn tộc — bại tướng bốn đại gia tộc từng bị hắn chất thành đống người ở Hư Thần giới — tới vây giết, khiến hắn ứa máu vì thua kém phù văn. Nhóc Tỳ dụ địch vào dãy núi dung nham, vung bảo kính kích động cốt tháp nổi giận đánh vỡ bảo cụ Côn tộc khiến chúng rơi xuống dung nham chết, rồi dùng Cốt Tiễn màu vàng chờ trước cắt đôi hai kẻ trốn thoát. Hơn một tháng trong di tích trôi qua, dung nham lắng lại, cốt tháp hút sạch địa hỏa co lại thành tiểu tháp trắng như ngọc, không phản ứng gì nên hắn đành quấn lên tóc làm trang sức. Khi tới Phân Bảo Nhai — ngọn nguồn di tích nơi nhiều thiên tài tụ tập, tiếng già nua của Quỷ gia bỗng vang bên tai đòi 'kiếm của ta', khiến hắn kinh ngạc vì Quỷ gia đáng lẽ ở lại Bổ Thiên các."},{"chuong":144,"tieuDe":"Phân Bảo Nhai","tomTat":"Nhóc Tỳ chiếu bảo kính Toan Nghê phát hiện chuỗi ký tự đen nguyền rủa của Bổ Thiên các trên trán, buộc phải tìm một thanh kiếm gãy nếu không sẽ chết. Nó lên Phân Bảo Nhai — ngọn núi đầy hài cốt thiên tài cổ đại — đối đầu các thiên tài dị tộc như Tất Phương, Tỳ Hưu, Bạo Viên và chim thần màu vàng. Nhóc Tỳ đánh bại cây thực vật kỳ lạ bằng tia chớp vàng, đoạt chiến mâu; bảo cụ Cánh Kim Ô xuất thế bị chim thần màu vàng cướp đi. Nó chinh chiến giết sạch hai ba mươi thiên tài ba tộc Ly-Uyên-Mông bằng Long Giao tiễn rồi leo lên đỉnh vùng ngừng chiến. Tại rừng đá, Tất Phương đoạt được pháp trượng đỏ như máu; kẻ tranh đoạt bừa bị Phân Bảo Nhai đánh thành thịt nát. Người phong ấn ba tộc và Bạch Hổ hẹn giết Nhóc Tỳ khi rời khỏi, nó ngạo nghễ nhổ nước bọt đáp trả."},{"chuong":145,"tieuDe":"Kiếm Cổ","tomTat":"Trong rừng đá Thượng Cổ đầy đồ án Kim Ô trục điện, Tù Ngưu vượt biển, Côn Bằng giương cánh, Nhóc Tỳ dùng phù văn Nguyên Thủy Chân Giải câu thông tìm bảo cụ nhưng vô dụng. Nó đi trêu chọc đám Người phong ấn đã bị nó giết con cháu và con Bạo Viên đen thui, khiến họ tức hộc máu nhưng không dám động thủ vì đây là nơi ngừng chiến. Nghe văng vẳng “Kiếm của ta…”, tảng đá dưới chân nứt vỡ lộ ra Kiếm Cổ — đoạn sắt gãy rỉ sét nặng mấy vạn cân mang đại sát khí chư thánh. Khi rút kiếm, sát khí ngập trời xâm nhập suýt xoắn nát thân, tiểu tháp trên tóc đột nhiên sáng lên xua tan toàn bộ. Bạch Hổ giải thích về hắc sát chiến trường cổ. Cuối chương công chúa Hỏa quốc Hỏa Linh Nhi dẫn nhóm người vào rừng đá; Nhóc Tỳ gọi nàng là “sư muội” và tuyên bố bảo kê."},{"chuong":146,"tieuDe":"Chương 146","tomTat":"Công chúa Hỏa quốc xinh đẹp đi cạnh Nhóc Tỳ khiến nhiều người khó chịu; nhóm Người phong ấn bàn nhau bằng mọi giá diệt Nhóc Tỳ trước khi hắn về Bổ Thiên các. Nhóc Tỳ dẫn Hỏa Linh Nhi cùng các sư huynh sư tỷ đi trêu chọc đám Người phong ấn, kể đã giết cháu/hậu bối của họ. Một tảng đá lớn nứt ra lộ Cốt hoàn Thượng Cổ màu xanh da trời thiếu một miếng, Hỏa Linh Nhi giành đeo lên tay dù sói con muốn tháo cho Nhóc Tỳ. Đại Hồng Điểu đầy máu bay tới báo Sư Tử chín đầu và Tử Điêu sắp bị phân thây, Nhóc Tỳ nhờ Hỏa Linh Nhi dùng thủ hạ Người phong ấn giúp việc rồi cưỡi chim bay đi. Tại chiến trường bên chân núi Phân Bảo Nhai, đám Thái Cổ di chủng của Nhóc Tỳ bị đánh trọng thương; nó đối đầu Bạch Hổ, Bạo Viên và chim thần màu vàng, hỏi chim thần có mang huyết thống thuần huyết Thái Cổ thần sơn không."},{"chuong":147,"tieuDe":"Chương 147","tomTat":"Con chim thần màu vàng ra mặt với mắt như vòng xoáy nuốt linh hồn khiến Đại Hồng Điểu choáng váng. Bạo Viên nắm Kim Cương thần lực nôn nóng xông lên đánh Nhóc Tỳ trước; Nhóc Tỳ phản đòn bằng sấm sét bảo kính Toan Nghê phá màn sáng chân Bạo Viên rồi dùng Cốt Tiễn màu vàng chém máu văng. Bạo Viên kích hoạt phù văn Kim Cương phình to ba mươi mét tung sóng trùng kích, nhưng Nhóc Tỳ dùng phù văn Nguyên Thủy Chân Giải với trăng bạc bao phủ, đấm thủng máu thịt Bạo Viên và đánh nổ chuông đen của nó. Nhóc Tỳ nhấc Bạo Viên đập trái đập phải như xách người rơm, khiến nó teo nhỏ. Khi bầy Thái Cổ di chủng vây công, Nhóc Tỳ cắt đôi một mãnh thú và thiêu một hung cầm, nhưng lưng bị Bạch Hổ lén xé tận xương. Nổi giận, Nhóc Tỳ nghiền nát Bạo Viên rồi tiến đánh Bạch Hổ; Bạch Hổ hóa luồng sáng trắng tham chiến."},{"chuong":148,"tieuDe":"Kiếm Gãy Chém Bát Phương","tomTat":"Bạch Hổ (Thái Cổ di chủng thuộc tính kim, cảnh giới ngang Người phong ấn) áp đảo Nhóc Tỳ bằng tốc độ và sức mạnh, phun khí kim loại hóa giải tia chớp. Nó tế ra 28 chiến mâu trắng bạc do răng nanh hóa thành vây đâm, mặc bảo y Bạch Hổ phòng ngự cực mạnh; Long Giao tiễn của Nhóc Tỳ phá được bảo y khiến Bạch Hổ chảy máu. Bạch Hổ lấy túi Càn Khôn hút vạn vật định đoạt binh khí, buộc Nhóc Tỳ rút Kiếm Cổ — một nhát chém đứt toàn bộ 28 chiến mâu, phá bảo ấn nổ tung. Nhóc Tỳ chém đứt nửa thân Bạch Hổ, sai Đại Hồng tiếp lấy máu thịt đại bổ, rồi đoạt túi Càn Khôn, mưu tính bắt hết Thái Cổ di chủng trong Bách Đoạn sơn nhét vào. Cuối chương chim khổng lồ màu vàng xuất trận như Thần vương, ra lệnh mười mấy di chủng giết Nhóc Tỳ và tuyên bố sẽ cướp kiếm gãy."},{"chuong":149,"tieuDe":"Kim Sí Bằng Điểu","tomTat":"Khi Bạch Hổ chỉ còn nửa thân thể cầu cứu, con chim khổng lồ màu vàng lạnh nhạt bỏ mặc, để mặc Nhóc Tỳ vung kiếm gãy chém đứt đầu hắn; trước khi chết Bạch Hổ tự hủy nguyên thủy phù cốt khiến Nhóc Tỳ tiếc nuối, còn thân thể thì ném cho Đại Hồng ăn bổ. Nhóc Tỳ nhục mạ chim vàng là 'con gà con', khiến cả đám Thái Cổ di chủng sững sờ trước sự xúc phạm một Kim Sí Đại Bằng. Chim vàng ra lệnh giết, hơn mười di chủng cùng xông tới nhưng bị kiếm khí của Nhóc Tỳ phá tan, một tên nổ tung thành sương máu. Kim Sí Bằng điểu phun ra Nguyên Từ Phong khắc chế binh khí kim loại, nhưng kiếm gãy pháp khí Thượng Cổ vẫn thoát khỏi trói buộc, hai bảo cụ đỉnh cấp giao chiến kinh thiên. Sư Tử chín đầu tiết lộ chim vàng là bán huyết Kim Bằng, cảnh giới cao hơn Nhóc Tỳ, và nó lại tung ra bảo phiến vàng tế luyện từ cánh Kim Ô, thần hỏa ngập trời hóa mặt đất thành dung nham. Sau va chạm đầu tiên cả hai đều trọng thương, kiếm gãy tróc rỉ sét lộ thân kiếm đen thui khiến Bằng điểu khiếp sợ vì uy năng tăng dần, và nó nhận ra Nhóc Tỳ nãy giờ giả ngốc với thân thể mạnh ngang thần thú thuần huyết. Bằng điểu dùng đòn hút hồn hai mắt xoáy vàng nhưng bị Nhóc Tỳ phun tinh khí chí cương chí dương kèm tia chớp phá giải, rồi tung cú đá chặn cánh thần sắc hơn thiên đao khiến cả hai bay ngược ra, mở đường cho đợt lao xuống móng vuốt tiếp theo."},{"chuong":150,"tieuDe":"Anh Dũng Phục Bằng","tomTat":"Nhóc Tỳ đứng trên bảo kính Toan Nghê quyết chiến sinh tử với Kim Sí Bằng điểu, đấu cả về phù văn lẫn thân thể qua hơn tám trăm hiệp, ngang sức bất phân thắng bại. Nó dùng cối xay màu bạc nghiền ép mưa lông vàng, kết hợp trăng bạc và sấm sét chồng chất bảo thuật, dùng Thanh Thiên Bằng chụp nát thần kiếm vàng của đối thủ. Có lúc bị móng vuốt suýt xé bụng lòi ruột nhưng vận thần hi khép vết thương không để sẹo. Khi Kim Bằng đuối sức, Nhóc Tỳ bùng phát phản công, đánh thủng bụng, cưỡi lưng ôm cổ nện đầu lâu khiến nó phun máu. Kim Bằng gọi hai bảo cụ Nguyên Từ Phong và cánh Kim Ô về nghênh chiến, nhưng đúng lúc thanh kiếm gãy tỉnh giấc tróc rỉ sét khiến uy thế tăng vọt. Cánh Kim Ô cảm nhận điều kỳ lạ bỏ chạy mất, Nhóc Tỳ tự tay phá hủy Nguyên Từ Phong, và tiểu tháp bí ẩn trên tóc âm thầm nuốt năng lượng trận chiến. Cuối cùng Nhóc Tỳ dùng kiếm gãy chém đứt một cánh khổng lồ của Kim Bằng, phân định thắng bại."},{"chuong":151,"tieuDe":"Quét Sạch","tomTat":"Nhóc Tỳ chân đạp bảo kính Toan Nghê chém đứt đầu Kim Sí Đại Bằng (chim thần bán huyết) sau khi nó tự hủy phù cốt để không cho đoạt bảo thuật. Hơn mười ba con Thái Cổ di chủng chia bốn phương tám hướng bỏ chạy, Nhóc Tỳ cùng Sư Tử chín đầu, Đại Hồng Điểu, Tử Điêu và đám thú đuổi giết: Nhóc Tỳ giết bốn con, đám Sư Tử ngăn năm con. Nó thiêu đốt tinh khí thần tăng tốc đuổi giết hung cầm trong mây ép nổ tung, còn Đại Hồng Điểu dùng bảo cụ Hắc Oa giết ác điểu nhưng suýt mất mạng. Hỏa Linh Nhi cùng mấy Người phong ấn bức con hung cầm quay lại để Nhóc Tỳ giết, và kinh ngạc trước việc thiếu niên Nhân tộc giết cả Kim Sí Đại Bằng — Người phong ấn nhận định tiềm lực Nhóc Tỳ so với Nhân Hoàng lúc nhỏ chưa chắc đã kém. Cuối cùng toàn bộ di chủng gồm Kim Sí Đại Bằng và Bạch Hổ đều bị diệt sạch. Người phong ấn khuyên tận dụng máu huyết Kim Sí Đại Bằng làm bảo dược, cả đám tìm suối ninh nấu di chủng bồi bổ. Nhóc Tỳ trêu chọc Hỏa Linh Nhi đòi kết bái với Nhân Hoàng khiến nàng nổi giận."},{"chuong":152,"tieuDe":"Tiến Quân","tomTat":"Sau trận chiến, Hỏa Linh Nhi ngăn không cho ăn Kim Sí Đại Bằng ngay, muốn dùng bài thuốc cổ truyền hầm với bảo dược để phát huy dược hiệu. Đám di chủng xử lý chiến lợi phẩm và ăn thịt Bạo Viên khiến xương gãy liền lại, vết thương khép, Tử Điêu và Sư Tử chín đầu tăng huyết mạch. Nhóc Tỳ đoạt được túi Càn Khôn của bộ tộc Bạch Hổ, tế luyện thành công, thử thu đá mười vạn cân và cả ngọn núi nhỏ, còn hút Đại Hồng Điểu vào túi trêu chọc. Nó bế tắc ở Động Thiên thứ chín, được khuyên tiến đại cảnh giới nhưng muốn ăn thịt Đại Bằng để trùng kích lần nữa. Nhóc Tỳ nấu canh hổ cốt từ chân Bạch Hổ ba canh giờ, dùng bảo thuật làm tan xương, cả đám tranh uống rồi vài con Tử Điêu, Hỏa Nha đột phá bình cảnh. Sáng hôm sau Nhóc Tỳ tuyên bố tìm linh dược, hé lộ Bất Lão Thần Tuyền trong Bách Thảo viên — cấm địa nguy hiểm chỉ Thái Cổ thú non thuần huyết mới dám vào. Đoàn người tiến quân tới gần Bách Thảo viên, Nhóc Tỳ lộ bản chất mê tiền đòi tất cả là của mình."},{"chuong":153,"tieuDe":"Thần Viên","tomTat":"Nhóm Nhóc Tỳ, Hỏa Linh Nhi, Sư Tử chín đầu cùng nhiều Người phong ấn tới gần Bách Thảo viên (Thần viên) khí tức thần thánh. Một sinh linh ba đầu hung tàn thuộc chủ mạch Linh tộc — hậu duệ Thái Cổ vương mạch mạnh nhất — xuất hiện, đang xé xác ăn sống một con Bích Lân Báo rồi tấn công đám người, chặt đứt một tay của Ngũ lão. Nhóc Tỳ quát mọi người lui, một mình đấu chưởng với nó như hai mặt trời nhỏ giao kích, nện quyền làm vỡ xương vai đối phương; sinh linh tàn nhẫn tự giật đứt tay để thoát, xông vào Bách Thảo viên biến mất. Nhóc Tỳ trả lại tay gẫy cho Ngũ lão để nối lại nhờ linh dược, rồi dặn mọi người rời đi, một mình tiến vào Thần viên tìm Bất Lão Thần Tuyền ở trung tâm — nơi phù văn bảo cụ vô dụng, từ trường mạnh vặn vẹo hư không. Nó gặp thần điểu Tất Phương, bị dây leo tím thành tinh tấn công liền nhổ gãy nát, rồi gặp một tảng đá biết nói dính phấn hoa Thông Linh Thần Hoa mở linh trí; Nhóc Tỳ nhấc tảng đá theo, bảo nó kể về Thần viên."},{"chuong":154,"tieuDe":"Vườn Thuốc","tomTat":"Trong Thần viên, Nhóc Tỳ cầm khối Ngoan Thạch biết nói (do Thông Linh Thần Hoa điểm hóa) tra hỏi và biết cây thánh dược này cực hiếm, có thể điểm hóa linh trí và giúp cường giả ngộ đại đạo; nó vốn là bảo dược rơi vào Bất Lão Tuyền chiếm tinh hoa mà đột phá. Ngoan Thạch cho biết Bất Lão Tuyền nằm ở chỗ sâu nhất của vườn linh dược. Nhóc Tỳ ném Ngoan Thạch đập trúng một cường giả Vũ tộc thân người đầu chim cánh tím, giao đấu rồi nhổ trụi lông đối phương sau mười hiệp. Xông qua trường vực thủ hộ, nó thổ huyết ói bốn ngụm máu vẫn ăn tươi chín cây linh dược, đồng thời phát hiện nhiều thi thể sinh linh bị ăn. Một Hoàng Kim thú quát nó hái thuốc cho chủ nhân, Nhóc Tỳ đòi nộp hết thuốc khiến một giọng lạnh chí cường vang lên. Cuối cùng nó phát hiện thánh quang kim sắc chỗ sâu vườn thuốc — chính là Bất Lão Tuyền đang dậy sóng vàng, có nhiều sinh linh vây quanh tranh giành nước thần tuyền."},{"chuong":155,"tieuDe":"Chương 155","tomTat":"Ao Bất Lão Tuyền rộng một trượng vuông tỏa kim quang chói mắt như thái dương, nhiều sinh linh hình người, chim, thú cố tiến lại gần thần trì nhưng bị trường vực kinh khủng cản, còn phải đứng ngoài mấy trượng. Nhóc Tỳ đến kịp lúc, ngồi trên tảng đá xanh tính 'thu thuế'. Bị Hoàng Kim thú — Thần bộc Thái Cổ Thần Sơn — quát đe dọa, Nhóc Tỳ ném ngoan thạch (tảng đá biết nói cực cứng) ba lần trúng, làm chảy máu hốc mắt, gãy cằm rồi gãy sống mũi Hoàng Kim thú, cuối cùng quật nó ngất đi. Ngoan thạch không hề sứt mẻ khiến sinh linh nghi ngờ đây là Đả Thần Thạch trong truyền thuyết. Một thiếu nữ tóc tím khí tức kinh khủng, nghi là hung thú thuần huyết hóa hình người và là chủ nhân của Hoàng Kim thú, cảnh cáo và dọa giết Nhóc Tỳ, còn Nhóc Tỳ lại ngỏ ý muốn hàng phục nàng làm thần thú cưỡi. Cuối cùng Nhóc Tỳ đoạt túi da chứa hai ba chục gốc bảo dược, ngồi chờ thiếu nữ tóc tím lấy được Bất Lão Tuyền rồi mới ra tay đoạt."},{"chuong":156,"tieuDe":"Bất Lão Tuyền","tomTat":"Nhóc Tỳ (Thạch Hạo) ngồi bên Bất Lão Tuyền, ép các Thái Cổ di chủng đang bị Hoàng Kim thú cưỡng bức hái thuốc phải nộp hết linh dược đổi lấy bình an. Thiếu nữ tóc tím phẫn nộ vì bị chia chác linh dược; Nhóc Tỳ ném cự thạch tấn công nàng nhưng bị trường vực đánh nát thành bột, đành không xuất thủ để chờ cướp sạch về sau. Nó tra hỏi Hoàng Kim thú, dùng ngoan thạch bẻ gãy đoạt hai sừng vàng kim làm thuốc dẫn rồi đập ngất con thú. Thiếu nữ tóc tím kích động các sinh linh liên thủ diệt Nhóc Tỳ trước, buộc nó đeo túi da thú tiến vào trường vực cạnh tranh công bằng, dọc đường thấy tám thi hài nổ tung. Càng vào trong ánh vàng càng đậm, một con chim thần mắt sắc bén xé xác một sinh linh rồi nuốt trái tim bổ sung tinh khí thần. Các sinh linh tiếp cận Bất Lão Tuyền, quyết chiến bùng nổ; Nhóc Tỳ bị móng vuốt đen tấn công và hò hét đòi hàng phục hung thú lẫn chim thần thuần huyết."},{"chuong":157,"tieuDe":"Tất Cả Đều Là Của Ta!","tomTat":"Thạch Hạo (Nhóc Tỳ) giao chiến kịch liệt với Chư Kiền — một Thái Cổ hung thú non thuần huyết mặt người một mắt dọc, thân báo đuôi giao long — cứng chọi cứng làm đất nứt rung ầm ầm, đánh trọng thương và xé được một tảng huyết nhục bảo dược từ tay nó. Cậu dùng Đả Thần Thạch (ngoan thạch) đập địch phát nào trúng phát ấy, còn ném trúng trán thiếu nữ tóc tím hai lần khiến nàng nổi hai cục u như cặp sừng rồng, lần đầu đời bị nhục. Chim thần Tất Phương lao tới nhưng chỉ nhằm đánh Chư Kiền vì đại thù, không liên thủ với ai. Cả nhóm xông vào thần trì Bất Lão Tuyền chịu trường vực khiến động tác chậm chạp và thân thể đau nhức, nhưng phát hiện thần tuyền đã khô cạn chỉ còn bùn cát vàng kim. Thạch Hạo và Ngoan thạch tranh nhau ăn bùn cát, rồi đào ra con rồng nhỏ màu vàng — Bất Lão Tuyền đang lột xác hóa hình; cậu ra tay trước cắn đứt đuôi rồng, rồng gầm thét phá tung tuyền trì rồi hóa hào quang bỏ chạy, cả nhóm đuổi theo trong khi Thạch Hạo giữ chặt đuôi rồng và hò hét đều là của ta."},{"chuong":158,"tieuDe":"Chương 158","tomTat":"Đuôi rồng vàng phân rã thành năm con rồng nhỏ định chạy, Nhóc Tỳ chụp được nhét vào miệng đe dọa rồi nhốt vào bình ngọc; Đả Thần Thạch xác nhận đây là năm giọt Bất Lão Tuyền, còn con rồng vàng lớn (chính chủ) đã hóa hình tỉnh giấc chạy thoát, tương lai có thể thành Tế Linh hay thần linh. Hai đứa tranh nhau ăn sạch cát vàng đã ngâm Bất Lão Tuyền, đào sâu quá ba mét khiến ao thần thành đất bình thường. Ngoan thạch sau khi ăn no buột miệng khoe, bị tra khảo phải thú nhận bốn lần trộm cát thần và việc cắn Thông Linh Hoa rồi chôn xuống đất ăn hết, khiến Nhóc Tỳ giận dữ giẫm đạp. Nhóc Tỳ ra ngoài thu mười một túi cát thần vào túi Càn khôn, quay lại đào tám cây linh dược nguyên rễ, dự tính đem về Thạch thôn tạo đất lành cho Nhân tộc và phân năm giọt cho tộc trưởng, Liễu thần cùng nhóm Đại Tráng. Nó giao chiến Chư Kiền xé thêm huyết nhục bảo dược, đập trán thiếu nữ tóc tím mọc ba bướu rồi bị các sinh linh thuần huyết vây truy sát phải bỏ chạy. Cuối chương, Nhóc Tỳ còn nhổ lông Tất Phương làm quả cầu và lừa Li Long để bóc hai vảy rồng dính máu, kết luận rằng đám sinh linh này tính nết xấu xa khó sống chung."},{"chuong":159,"tieuDe":"Cấm Khu Thiên Cốt","tomTat":"Nhóc Tỳ trộm hai miếng thịt của Chư Kiền rồi trốn khỏi Thần viên/Bách Thảo viên, bị các sinh linh thuần huyết Chư Kiền, Tất Phương, Li Long và thiếu nữ tóc tím hợp sức bao vây truy sát. Ra khỏi vùng tịnh thổ, đám sinh linh bùng phù văn dày đặc như thần khiến nó nhận ra đó là đặc thù khi mở Động Thiên thứ chín; bị đánh hộc máu, nó đành dùng Súc Địa Phù dán vào lòng bàn chân hóa tia sáng thoát thân, khiến bọn Tất Phương sững sờ. Phù này cướp từ nam tử áo xanh Côn tộc trong hồi tưởng — kẻ cùng Người phong ấn Cai tộc truy sát nó, bị nó dùng Long Giao Tiễn đánh chết. Nó dọa luyện ngoan thạch (Đả Thần Thạch) thành chí bảo ép nó thu nhỏ bằng đốt ngón tay, quấn cạnh tháp nhỏ bí ẩn. Sau một đêm, Nhóc Tỳ tiến vào cấm khu Thiên Cốt, phát hiện vùng sương mù xám chất đầy xương trắng và sâu bên trong có sinh linh thuần huyết giao chiến. Ở tuyến khác, thiếu niên Nhân loại Thạch Nghị (Trùng Đồng giả) của Võ Vương phủ đẩy lui thần thú xanh và trấn áp Liệt Thiên Ma Điệp thuần huyết năm lần bằng thần quang ngũ sắc của Ngũ Sắc Khổng Tước Vương, khó gặp địch thủ trong cấm khu."},{"chuong":160,"tieuDe":"Trùng Đồng","tomTat":"Liệt Thiên Ma Điệp — hậu duệ ma thần thời Thái Cổ đã năm lần thất bại — dốc toàn bộ thần lực khiêu chiến trận quyết đấu cuối cùng với Thạch Nghị, hai cánh hóa thành tiên kiếm cùng bảo thuật lôi điện cực mạnh. Thạch Nghị dùng thần thông lôi điện trấn giáo Vũ tộc đối lôi, uy lực hơn cả Vũ tộc, khiến chúng nhân bàn tán về năm loại bảo thuật trấn tộc của hắn mà hai loại vẫn còn bí ẩn. Hắn mở Trùng Đồng Khai Thiên phóng lưới phù văn trói cứng bướm ma, rồi hiển hóa năm Động Thiên, mỗi cái tẩm bổ một sinh linh chí tôn hóa từ phù văn, đánh bại địch lần thứ sáu và thả bướm ma vào vùng cấm Thiên Cốt. Bên ngoài đám đông, Nhóc Tỳ nhai bùn cát thần màu vàng luyện hóa để nâng thực lực, khiến Đả Thần Thạch than đau lòng và cảm nhận cậu chôn giấu điều gì đó rất sâu. Sau nửa canh giờ, một tiếng nổ kinh thiên làm toàn tiểu thế giới rung chuyển, các thông đạo cửa vàng biến mất và các vực nối thông thành chỉnh thể — Bách Đoạn sơn hiện nguyên hình. Thời gian mở cửa sắp kết thúc, dân bản địa mạnh mẽ được giải thoát bắt đầu tàn sát các thiên tài ngoại lai."},{"chuong":161,"tieuDe":"Thế Giới Màu Máu","tomTat":"Bách Đoạn sơn vốn là bảo địa để thiên tài các tộc tìm cơ duyên nay đột nhiên dỡ phong ấn, hóa thành thế giới màu máu — hung thú, ác điểu và sinh vật hình người lâu năm từ Phân Bảo Nhai, Bách Thảo Viên, cấm khu Thiên Cốt đồng loạt lao ra săn giết. Hắc Hống, Long Giác Sư, Bích Nhãn Kim Tình thú, Kim Sí Đại Bằng cùng đàn Bức Long đại khai sát giới, thiên tài các tộc tử vong quá nửa. Nhóc Tỳ dùng đại thần thông che giấu khí tức thoát khỏi cấm khu Thiên Cốt, dọc đường cứu bất thành một thiếu nữ Nhân tộc bị Cứ Xỉ điểu cắn đứt. Nó săn dị thú chém đầu gom huyết nhục, đã thu 12 con hung thú vào túi Càn Khôn làm bảo dược. Nhóc Tỳ phát hiện chim thần Tất Phương đang hút chất lỏng quả trứng bạc, liền dùng túi Càn Khôn cướp trứng và giao đấu với Tất Phương khiến cả vùng núi và tổ chim nổ tung. Chủ nhân quả trứng (hung cầm trắng bạc) trở về buộc Tất Phương bỏ chạy; cuối chương Nhóc Tỳ phát hiện Chư Kiền, Li Long tiến sâu vào Bách Đoạn sơn và một thiếu nữ tóc tím được 108 vòng thần hoàn bao phủ, cân nhắc giao thủ."},{"chuong":162,"tieuDe":"Cắn Lỗ Tai","tomTat":"Nhóc Tỳ theo dõi thiếu nữ áo tím lên một ngọn Linh sơn linh khí sôi trào, kinh ngạc trước trình độ phù văn phá cấm chế không gây tiếng động của nàng. Dọc đường nó phát hiện đầm nước lạnh nuôi giao thú và bãi xương khoảng hai mươi con giao thú, nhận ra có sinh linh cực mạnh xem chúng làm thức ăn; đồng thời đào được bốn gốc Hắc Giao thảo và thu Ngân Vũ thảo cực phẩm vào túi Càn Khôn. Thiếu nữ áo tím phá cấm chế hang tổ chim nhưng bên trong trống trơn, tính kế trừng trị tên Nhân loại. Nhóc Tỳ liền tập kích, nhảy lên lưng nàng dùng túi Càn Khôn, tiểu tháp và Đả Thần Thạch chế áp, cắn đứt bông tai thần kim và hút bảo huyết vành tai khiến nàng xấu hổ gần ngất, phù văn mờ đi. Nàng nổi thịnh nộ dùng bảo kính đối chiến làm cả tòa núi nổ tung; hai người rơi xuống một động thiên khác có tổ chim thứ hai chứa cái kén phát sáng. Nhóc Tỳ vọt tới cướp kén rồi bỏ chạy, thiếu nữ áo tím đuổi theo."},{"chuong":163,"tieuDe":"Trung Tâm Bách Đoạn","tomTat":"Nhóc Tỳ ôm cái kén phát sáng vừa trộm được chạy trốn khỏi thiếu nữ áo tím, sau hơn nửa canh giờ vật lộn mới cắt được đuôi vì chỉ có một mình nàng đuổi theo. Đả Thần Thạch khoe đã cắn vành tai cướp được chiếc bông tai bảo châu tím của nàng, đồng thời nhận định cái kén là tài liệu quý không kém Thiên Tằm Ti. Nhóc Tỳ tiến vào khu trung tâm Bách Đoạn sơn đầy sát cơ, nơi các lão quái Thú vương ẩn hang phục kích và một thiên tài bị Khổng Tước năm màu nuốt chửng. Các hung thú thuần huyết lần lượt bị trọng thương: Chư Kiền bị sói già khoét lưng, Tất Phương bị Khổng Tước xé rách phòng ngự, Li Long bị bầy khỉ kim quang cùng thần hầu vàng cầm thần mâu vạn cân nện nát đuôi nên phải tự chặt đuôi bỏ chạy. Nhóc Tỳ bất ngờ đối đầu Cổ thụ Thiết Huyết có linh tính, cây phóng rễ cây bảo cụ rồi nổ tung cả khu rừng khiến nó phun máu, hai canh giờ sau mới thoát thân trong tình trạng máu loang lổ suýt chết. Sau hai ngày ẩn núp, nó thấy các sinh linh cùng Liệt Thiên Ma Điệp, Bồ Ma thụ, Thạch Nghị và thiếu nữ áo tím đều dốc sức chạy về nơi phong ấn trung tâm. Cuối chương, Đại Hồng Điểu truyền âm gọi Nhóc Tỳ, trên lưng chở Hỏa Linh Nhi và Sư Tử chín đầu hiện ra từ hư không."},{"chuong":164,"tieuDe":"Bảo Địa Của Thần Hầu","tomTat":"Nhóc Tỳ đoàn tụ nhóm bạn sau nhiều lần suýt chết bởi cổ thụ Thiết Huyết, dùng Đả Thần Thạch nện đầu Đại Hồng Điểu nhưng ngoan thạch lại kêu đau vì đầu chim cứng như sắt. Nhóm kể lại hành trình thoát thú triều nhờ hai dị bảo: thuyền Xuyên Vân của chim Loan năm màu và tấm thảm thần tàng hình do Nhân Hoàng Hỏa quốc ban cho Hỏa Linh Nhi. Quyết ở lại Bách Đoạn sơn tìm bảo vật, cả nhóm nhận thấy nhiều sinh linh thuần huyết và vương giả tụ tập về khu trung tâm nơi bầy khỉ trấn giữ. Dùng thảm thần tiếp cận, họ phát hiện vùng tịnh thổ bồng lai với hồ linh dịch và bốn cây đào tiên bạc phát sáng có quả đào bạc chấm vàng kim. Đả Thần Thạch tiết lộ đây là lão thánh dược Bách Thảo Viên tái sinh, sắp lột xác thành thánh dược có thể khiến người thoát thai hoán cốt. Một con khỉ cầm chiến mâu vàng bổ ra, trận đại chiến giành thánh dược bùng nổ; Nhóc Tỳ chủ trương chỉ lấy thánh dược, không nên sát phạt."},{"chuong":165,"tieuDe":"Rượu Hầu Nhi","tomTat":"Con khỉ vàng Thần Hầu vương hùng cứ vùng núi có linh hồ, tịnh thổ và bốn gốc thánh dược, cầm chiến mâu vàng đơn thương độc mã chống lại nhiều di chủng Vương giả cùng tới cướp thánh dược. Mãng Ngưu, Khổng Tước năm màu, Kim Sí Đại Bằng, Hắc Hống lần lượt ra tay đều bị Thần Hầu dùng Pháp Thiên Tướng Địa biến thân to như núi đánh bại; sau đó các con cùng Thứ Thú trắng bạc và Cổ thụ Thiết Huyết tập hợp quần chiến khiến thiên địa tối tăm. Nhân lúc loạn cục, nhóm Hỏa Linh Nhi dùng thảm thần da Hư Không thú lặng lẽ tiến vào tịnh thổ đục nước béo cò, thiếu nữ tóc tím dùng sừng vàng phá cấm chế phù văn. Sói con trong ngực Hỏa Linh Nhi kích động chỉ hướng cổ thụ có Nấm Đầu Khỉ nhưng lại ngăn Nhóc Tỳ hái nấm mà chỉ vào một thân cây khô có phù văn khủng bố. Nhóc Tỳ dùng kiếm gãy phá phù văn rạch hốc cây, phát hiện bên trong đầy chất lỏng ngọc tủy thơm ngát chính là Rượu Hầu Nhi, tuyệt thế bảo dược ủ từ nhiều linh dược và hương đào tiên. Nhóc Tỳ dùng túi Càn Khôn che kín giấu mùi thơm rồi hớp một ngụm, cảm thấy trời đất quay cuồng, hào quang phát ra từ lỗ chân lông, tin sẽ sớm mở được Động Thiên thứ chín và khôi phục Chí Tôn Cốt."},{"chuong":166,"tieuDe":"Thu Hoạch Rất Lớn","tomTat":"Nhóc Tỳ tìm được một hốc cây cổ thụ đầy rượu Hầu Nhi óng ánh như hổ phách, do bầy thần hầu ủ men từ mấy chục loại linh dược; nó nếm một ngụm rồi tỉnh táo, dùng kiếm gãy khoét lỗ phong kín và nhổ cả gốc cổ thụ cho vào túi Càn Khôn. Đại Hồng Điểu, Sư Tử chín đầu, Hỏa Nha cùng Hỏa Linh Nhi — con gái Nhân Hoàng từng uống qua rượu Hầu Nhi — đều ngẩn ngơ khiếp sợ trước phẩm chất có một không hai. Bên linh hồ trong tịnh thổ, Thần Hầu vương một mình đại chiến đám vương giả với thân đao thương bất nhập, trong khi bầy khỉ bảo vệ bốn cây đào tiên bạc đại chiến các sinh linh thuần huyết như Chư Kiền, Li Long, Tất Phương và Liệt Thiên Ma Điệp. Thiếu niên Nhân tộc Thạch Nghị mắt hai con ngươi dùng phù văn ổn định hư không khiến bảo cụ đối phương bất động, rồi chém đục thủng ngực khiến một thần hầu thủ lĩnh nổ tung, khiến mọi người kinh hãi cảnh giác. Sói con đánh hơi dẫn Nhóc Tỳ tới hốc cây thứ hai chứa rượu mới ủ kèm đào tiên bạc, nó thu thêm hơn mười gốc nấm Đầu Khỉ. Nhóc Tỳ dự tính mang rượu về Thạch thôn cho tộc trưởng, Lâm Hổ thúc và Phi Giao thúc nếm, chỉ tiếc nuối vẫn chưa đoạt được cây đào tiên ngay trước mặt."},{"chuong":167,"tieuDe":"Bồ Ma Thụ","tomTat":"Trong tịnh thổ hang ổ thần hầu, nhiều phe kỳ tài đại náo tranh đoạt bốn gốc tiểu thánh dược mà đàn khỉ vàng của Thần Hầu vương từng đoạt được. Li Long bị thần hầu vàng cắn vào chiếc đuôi từng bị Thần Hầu vương đâm mâu nên máu phun xối xả, liền cắn gãy răng nanh và dùng bảo cụ chém giết bầy khỉ; ba phương Liệt Thiên Ma Điệp, Tất Phương và khỉ vàng hỗn chiến, Chư Kiền tắm máu chiến đấu, Thạch Nghị đánh đâu thắng đó. Nhóc Tỳ đứng quan sát thì bị Bồ Ma thụ tập kích, những đóa hoa tuyết là Ma Tu nguyền rủa cắm rễ trên cánh tay phải để hút tinh khí thần. Nhóc Tỳ dùng cốt văn Nguyên Thủy Chân Giải ép hạt Ma Tu ra rồi cắn nhai nuốt luôn, dùng bảo kính Toan Nghê gặm hạt còn lại, lao vào cận chiến dùng kiếm gãy đánh lộ pháp trượng cháy đen — di vật của Ma tôn Bồ Ma thụ thời Thái Cổ. Nhóc Tỳ ăn ngấu nghiến thân cây, cắn thủng kéo rách nhánh khiến Bồ Ma thụ chịu không nổi, thu rễ và pháp trượng im lặng rút lui. Ven linh hồ Thạch Nghị xuất Bệ Ngạn và Kim Bằng đoạt gốc thánh dược màu bạc, còn Nhóc Tỳ đột nhiên bộc phát, cắt đứt một ngọn núi ném về phía đám người tranh thánh dược."},{"chuong":168,"tieuDe":"Đoạt Được Thánh Dược","tomTat":"Một ngọn núi từ trên linh hồ đè xuống mở màn hỗn chiến; Nhóc Tỳ thu ấu thần vào túi Càn Khôn rồi định thu cả bốn gốc đào tiên màu bạc nhưng thất bại. Các lão bất tử ẩn nấp lộ diện tranh đoạt: sói già, Hỉ Thước biến lớn như Côn Bằng, Giao già cùng nhiều sinh vật ngang tàng. Thần Hầu vương giăng đại trận Phong Thiên khóa chặt nơi đây để hốt gọn kẻ tranh dược, lần lượt đánh bại Tất Phương (tát nổ nửa người), Li Long (bắn kim thần) và Chư Kiền (chém đứt đuôi). Giao già — đại sư trận pháp Hầu vương tưởng đã chết — phá vỡ đại trận, các lão Vương như Mãng Ngưu và Cổ thụ Thiết Huyết liên hợp quần chiến. Thiếu nữ áo tím dùng Thánh giác phá phù đoạt đào, còn Thạch Nghị dùng thần năng con ngươi giam hư không rồi lấy bình bảo cốt hút đào tiên. Đúng lúc đó Nhóc Tỳ ném tiểu tháp trúng bình, xông tới cắn đứt một khúc đào bạc mà chạy. Cuối cùng cái kén trong túi Càn Khôn chấn động, tuyên bố ba cây đào tiên là của mình rồi thi đại trận hô Thu, giúp Nhóc Tỳ đoạt trọn một gốc đào tiên và dùng Súc Địa phù bỏ chạy mất dạng."},{"chuong":169,"tieuDe":"Sinh Linh Bên Trong Kén","tomTat":"Nhóc Tỳ trốn chạy mang theo cây đào tiên nhỏ ánh bạc pha vàng cùng chiếc kén phát sáng, thu cây đào vào túi Càn Khôn và ôm chặt kén đề phòng sinh linh bên trong ăn linh dược. Nhóm Hỏa Linh Nhi tới, Đại Hồng Điểu hăng hái phun lửa nướng kén để tra tấn moi thông tin, ép sinh linh khoác lác cuối cùng chịu thua. Phá kén lộ ra một con chim trọc lốc mỏ đỏ dài thân hơn hai mét không lông, tự xưng Thần linh và khoe thần thông vỡ áo nghĩa vô thượng biến Kỳ Lân hóa Phượng Hoàng. Hỏa Linh Nhi ngăn chặt kén vì tơ kén quý ngang tơ Thiên Tằm, sai Người phong ấn kéo thành cầu tơ bảy màu. Thiếu nữ áo tím xuất hiện lại khiến quái điểu chui trốn vào túi Càn Khôn, còn nàng hóa ánh sáng tím rời đi dọa trả thù. Ngoan Thạch tiết lộ quái điểu từ ngoại giới vào, từng là sư phụ của Thần Hầu vương và từng trộm Bất Lão Tuyền ở Bách Thảo Viên. Nhóc Tỳ đặt tên nó là Nhị Ngốc Tử rồi cả nhóm mở đại tiệc ngắm trăng, hầm bảo dược như thịt Kim Sí Đại Bằng và nấm Đầu Khỉ để làm cơ hội đột phá."},{"chuong":170,"tieuDe":"Chín Động Thiên","tomTat":"Nồi đen phát sáng, một con Kim Sí Đại Bằng hóa hình bay lên; trong nồi có thịt vàng óng, nấm Đầu Khỉ, Xích Lan, sâm Tuyết Ngọc — một lò bảo dược cực quý mà Nhóc Tỳ cùng Hỏa Linh Nhi và nhóm Người phong ấn cùng thưởng thức. Nhóc Tỳ uống liền 36 ly rượu Hầu Nhi (bảo dược do thần hầu ủ từ mấy chục loại linh dược), ăn cạn nồi thịt Đại Bằng, uống súp hổ cốt và cả đống linh dược, toàn thân bốc lửa tinh khí, thân thể trong suốt như Thần thai. Hắn nhảy xuống núi lửa đột phá cảnh giới Chín Động Thiên — chín tòa Động Thiên xếp chồng giao hòa thiên địa, cảnh giới chỉ có trong sách cổ khiến các sinh linh coi hắn ngang Chân Hống, Thao Thiết. Sau đột phá hắn cảm ngộ phù văn Nguyên Thủy Chân Giải, phù văn hóa ngân hà, hóa thân Côn Bằng/Chân Hống/Thao Thiết, thấy cả Chiến Thần Đồ Lục, trình độ phù văn tăng vọt. Chư Kiền trọng thương đuổi tới bị Nhóc Tỳ chém mất hai khối thịt thu vào túi Càn Khôn, Li Long tiếp viện dùng lưới trùm nhưng Hầu vương khỉ vàng thi triển Pháp Thiên Tượng Địa ngăn quyết đấu, hai hung thú Thái Cổ dùng bảo cụ Thái Cổ Thần Sơn trốn thoát. Nhóc Tỳ dùng Súc Địa phù chạy về thảm thần điều tức; tiểu thế giới rung động báo lối ra sắp mở trong một đến hai ngày, hắn tiếc chưa bắt được chim thần hay hung thú thuần huyết nào."},{"chuong":171,"tieuDe":"Ly Khai","tomTat":"Ngày cuối tiểu thế giới, dân bản địa điên cuồng săn giết thiên tài để thu hoạch thức ăn lần cuối, hơn tám phần thiên tài ngã xuống. Ở khu đầm lầy, Đại Hồng Điểu phát hiện hai cường giả Vũ tộc Vũ Côn và Vũ Văn Thành; Sư Tử chín đầu vừa đột phá lao xuống báo thù, hai người Vũ tộc mở phong ấn nhưng bị quy tắc Xích Thần Trật Tự cắt đôi hóa tro. Nhóc Tỳ chủ trì đuổi giết những người sống sót của tứ đại gia tộc, nhiều kẻ mở phong ấn cũng bị quy tắc giết sạch. Thần Hầu vương nổi giận vì mất hai tiểu thánh dược và rượu thần, chặn lối ra đại khai sát giới, đè chết Bích Ngọc Điểu và thi triển Pháp Thiên Tượng Địa giết trăm thiên tài. Tất Phương tạo thông đạo màu vàng chạy trốn nhưng bị Hầu vương phóng chiến mâu đâm nổ, phun máu lui về. Cuối cùng Nhân Hoàng vọng tiếng từ bên ngoài cánh cửa, lệnh Hầu vương tránh ra rồi đánh bay nó bằng làn sóng biển màu vàng khiến nó phun máu."},{"chuong":172,"tieuDe":"Uy Nghiêm Của Nhân Hoàng","tomTat":"Thần Hầu vương chặn cửa tiểu thế giới tàn sát thiên tài, một thanh âm uy nghiêm từ Nhân Hoàng ra lệnh nó tránh ra. Không phục, Hầu vương thi triển Pháp Thiên Tượng Địa dùng chiến mâu vàng đâm cửa, nhưng Nhân Hoàng hóa bàn tay ánh sáng vàng cách không vỗ nát chiến mâu và hai thần kiếm, đè trấn áp khiến nửa thân khỉ vàng suýt luyện hóa thành thiên địa tinh khí. Một sợi dây xích màu máu bí ẩn đâm tới, bị Nhân Hoàng bắn một chỉ đẩy lui; Hầu vương hoảng sợ thu kiêu ngạo phóng vào tận cùng tiểu thế giới không chặn cửa nữa. Sau hơn một tháng chinh chiến với tử vong hơn tám phần, sinh linh các tộc chen chúc thoát ly qua lối ra, chỉ Nhóc Tỳ không muốn rời vì còn nhiều linh dược để ăn. Nhóc Tỳ trêu Hỏa Linh Nhi đòi làm con rể rồi giả vờ ở lại, biến thành tên béo mập gặp Tiêu Thiên lấy phần Thái Nhất Chân Thủy thu vào túi Càn Khôn. Đại Hồng Điểu tự nhuộm đen lẩn ra ngoài nhưng bị Sư Tử chín đầu nhận diện, còn chiến xa cổ và Hoàng Kim thú từ Thái Cổ Thần Sơn đến đón sinh linh thuần huyết; cuối cùng quái điểu không lông dạy Nhóc Tỳ một tiểu thần thông hoàn thiện thuật biến hóa, hắn biến thành thiếu niên tráng kiện ngông nghênh đi ra."},{"chuong":173,"tieuDe":"Phong Ba","tomTat":"Nhóc Tỳ (Bóng Lông) dùng bảy mươi hai biến (đã hoàn thiện nhờ quái điểu không lông chỉ điểm) biến thành sinh linh da vàng nhạt lực lưỡng, trà trộn vào đám ra khỏi Bách Đoạn sơn mà không ai nhận ra, lừa được cả Hỏa Linh Nhi lẫn Sư Tử chín đầu để làm khán giả quan sát. Các bộ tộc đón đám thiên tài sống sót; Sư Tử chín đầu (bị chém rụng bốn đầu lâu vẫn mọc lại) lúng túng giấu việc đã ăn thịt tiểu Bạch Hổ khi một vị Vương Bạch Hổ của Tây Lăng Thú sơn gào thét chờ cháu. Vũ Tử Mạch được Vũ tộc đón ra, khóc báo tin trưởng lão, thiên tài và bốn Phong Ấn giả Vũ tộc chết sạch, chỉ nàng sống, tố cáo Nhóc Tỳ đoạt Thái Nhất Chân Thủy. Tứ đại gia tộc Côn, Ly, Mông, Uyên mất sạch thiên tài, thề diệt Nhóc Tỳ khiến hung danh nó lan khắp Bách Đoạn sơn. Thạch Nghị được tung hô là thần nhân Trùng Đồng chuyển thế, ra ngoài kéo theo con giao già Thái Cổ thu phục và một đoạn thánh dược; Võ Vương phủ họ Thạch nghênh đón hắn và tuyên chiến với Nhóc Tỳ. Cuối chương, Nhóc Tỳ lặng lẽ rời khu Võ Vương phủ, tự chọn con đường riêng, không cần linh dược và sự che chở."},{"chuong":174,"tieuDe":"Vô Đề","tomTat":"Nhóc Tỳ (Thạch Hạo) không vào Đoạn Không thành mà rời đi một mình để tránh nguy hiểm, ngồi trên tảng đá trong đầm lầy mở túi Càn Khôn kiểm kê chiến lợi phẩm — bảo cụ, linh dược, rượu Hầu Nhi, đào tiên, Thái Nhất Chân Thủy, huyết nhục di chủng và bảo dược huyết nhục của Chư Kiền — dự định dành một phần cho Thạch thôn. Nhị Ngốc Tử cảnh báo một tia hắc khí do ác quỷ nguyền rủa ẩn nơi xương trán nó sắp phát tác, với tu vi hiện tại khó chống, khiến nó nhớ lý do vào Bách Đoạn sơn là tìm kiếm cho lão quỷ và quyết định về Bổ Thiên các. Sau hai ngày tu hành ngộ đạo áo nghĩa Nguyên Thủy Chân Giải, nó mở ra Động Thiên thứ chín, thân thể càng mạnh. Gặp lại nhóm Đào Dã đang tìm nó khắp nơi, nó giao dịch để Đào Dã lấy thanh kiếm nguyền rủa; nhóm có một sư huynh đã chết ở Bách Đoạn sơn. Đào Dã bày phù cốt và tế đàn niệm thần chú hiến tế mở thông đạo đưa cả nhóm về Bổ Thiên các, xuất hiện trong cấm địa nơi Tế Linh tu hành. Các chủ nhiều năm bế quan lần đầu xuất hiện, công nhận công lao đào toàn bộ bùn cát Bất Lão Tuyền, cho Nhóc Tỳ tùy tiện ra vào Tàng Kinh các và sờ đầu nó than thở tương lai không xa Hoang vực sẽ đại loạn."},{"chuong":175,"tieuDe":"Vô Đề","tomTat":"Các chủ Bổ Thiên các dặn Nhóc Tỳ về nghỉ ngơi để họ chuẩn bị kỹ cứu Tế Linh Thượng Cổ đang khô vàng héo úa, sắp tọa hóa; họ dùng bùn cát Bất Lão Thần Tuyền Nhóc Tỳ mang về kết hợp linh vật quý và tro tàn thần vật Thượng Cổ. Nhóc Tỳ về khu đệ tử mới ở rừng trúc, hỏi thăm thì biết Bóng Lông đã gặm nát Linh Điền, ăn sạch thuốc quý Linh Sơn rồi bị lão tổ bắt trói. Ở Thiên Tài doanh, nó gặp lại Ngạn Tâm và Phiêu Tuyết trêu hỏi chuyện Bách Đoạn sơn, Chu Vũ Hào tái mặt lùi tránh, còn Thanh Phong đã tiến vào Động Thiên cảnh mừng rỡ chạy tới. Nhóc Tỳ theo Thanh Phong lên linh sơn Lôi đạo cầu xin lão tổ Mộ Viêm thả Bóng Lông; lão tổ cho nó xem thần phù ngưng kết cả đời Lôi đạo, khen thiên phú, cho phép chọn cốt thư Lôi đạo ở Tàng Kinh các, rồi thả Bóng Lông với lời dặn giấu bản thể. Nhóc Tỳ thử phóng tia chớp lên Nhị Ngốc Tử khiến nó bốc khói co giật. Cuối chương, Tiêu Thiên nghe chuyện Bách Đoạn sơn sinh hoài nghi, tìm hiểu ra sự thật suýt phun máu nên tới chờ đối chất trước phòng nó."},{"chuong":176,"tieuDe":"Kết Giao","tomTat":"Thanh Phong nhận ra thiếu niên áo bạc là Tiêu Thiên, đệ nhất thiên tài Bổ Thiên các; Tiêu Thiên chặn đường Nhóc Tỳ để báo thù vì bị đánh lén ở Hư Thần giới và tranh Thái Nhất Chân Thủy ở Bách Đoạn sơn. Nhóc Tỳ thừa nhận rồi ném Đả Thần Thạch trúng giữa trán Tiêu Thiên chuẩn xác không né được, khiến hắn nổi u cục còn Ngoan Thạch tự kêu đau. Khi giao chiến nghiêm túc, Nhóc Tỳ lộ cảnh giới đã mở Động Thiên thứ chín (xưa nay hiếm với Nhân tộc), áp chế hoàn toàn buộc Tiêu Thiên phải phục. Cả nhóm mở tiệc nướng và hầm di chủng Thái Cổ, thịt Đại Bằng hóa bảo dược phát sáng giúp Thanh Phong đột phá mở Động Thiên thứ hai. Uống rượu thần Hầu Nhi cả đám say bí tỉ, Tiêu Thiên gia nhập tiệc và suýt đột phá phải ép xuống. Sau nửa đêm, một lão nhân tóc bù xù đầu cắm kiếm gãy xuất hiện, than thở về Thượng Cổ rồi giải trừ nguyền rủa nơi trán Nhóc Tỳ; Nhóc Tỳ xin lão dạy bảo thuật cái thế vì đã tìm thấy thanh kiếm gãy giúp lão."},{"chuong":177,"tieuDe":"Bị Đánh","tomTat":"Đêm khuya, Quỷ gia — ông lão tóc đen bị cắm thanh kiếm cổ trên đỉnh đầu, tồn tại từ thời Thượng Cổ — đột nhiên nhấc bổng Nhóc Tỳ lên đập một trận nhừ tử, lần đầu trong đời nó bị người khác đánh. Nhóc Tỳ vận phù văn đan dệt phát sáng, dùng Đả Thần Thạch và Kim Giao tiễn phản kháng đều vô hiệu trước lão vững như bàn thạch. Không đánh nổi Quỷ gia, nó trút giận ném Đả Thần Thạch trúng đầu Tiêu Thiên và đánh bay Nhị Ngốc Tử đang cười hả hê, còn Bóng Lông vọt ra xa xem cuộc vui. Quỷ gia buông tay giải thích đánh là để rèn nền tảng vì Nhóc Tỳ tu hành quá nhanh, mở nhiều tiểu Động Thiên nên lưu lại mầm họa, dặn mỗi ngày đến Tế Linh đả tọa chữa lành và đi Tàng Kinh các học tập. Lão cảnh báo một ngày núi sông vạn vật nơi đây sẽ không còn tồn tại rồi bùng phát hào quang biến mất, chỉ để lại thanh kiếm gãy. Nhị Ngốc Tử nghi lớp keo nối kiếm gãy là thần cao nấu từ phượng uế lân giác và cảm giác tiểu tháp trên tóc Nhóc Tỳ như xương của Thiên Thần, khiến nó bị Nhóc Tỳ đánh để che giấu. Bình minh, Nhóc Tỳ giao thịt Đại Bằng cho Thanh Phong mang về rồi hướng về cấm địa linh sơn — nơi có Tàng Kinh các, thánh địa chí cao của Bổ Thiên các."},{"chuong":178,"tieuDe":"Kim Tuyền Ba Văn Công","tomTat":"Nhóc Tỳ đến Tàng Kinh các của Bổ Thiên các — tòa kiến trúc cổ giống Thần miếu vàng có cường giả canh giữ như hóa đá; chỉ mình nó được vào theo lệnh Các chủ, Nhị Ngốc Tử và Bóng Lông bị cản. Ông lão tóc rối giữ các khuyên nó tự tìm cơ duyên vì thần thông trấn giáo đã thất lạc từ lâu, tu tâm quan trọng hơn tu thân. Nhóc Tỳ ở lại đọc từng bộ cốt thư trong biển sách khổng lồ và tìm được quyển thượng Kim Tuyền Ba Văn công — pháp môn hộ thể mạnh thoát thai từ phù văn Kim Sí Đại Bằng do Nhân tộc biến đổi. Nó dung hợp công pháp này vào bảo thuật Thanh Thiên Bằng khiến trăng bạc hóa thành quả trứng thần, Ma cầm Thái Cổ lớn mạnh, càng gần bảo thuật Thiên Bằng chân chính. Đọc kinh văn còn giúp nó củng cố căn cơ, hóa giải mầm họa do đột phá quá nhanh ở Bách Đoạn sơn, và nhận ra trận đòn của Quỷ gia thực ra là giúp nó. Sau đó nó tìm đủ quyển trung và hạ, hoàn chỉnh bảo thuật mạnh hơn Toan Nghê, rồi phát hiện ghi chép về một khối xương nguyên thủy của Đại Bằng còn giữ phù văn trong bảo khố nên kích động truy hỏi vị trí."},{"chuong":179,"tieuDe":"Tế Linh Thức Tỉnh","tomTat":"Ông lão canh cửa Tàng Kinh các kể cho Nhóc Tỳ về bí ẩn khối kim cốt thất lạc — vật hiếm hai ngàn năm mới xuất hiện, được cho là đã thông linh tự chạy trốn, là nguồn gốc Kim Tuyền Ba Văn công. Nhóc Tỳ đọc hai khối cốt thư còn lại để lĩnh ngộ công pháp, sau khoảng một tháng luyện thành với vòng xoáy vàng hóa giải công kích và đôi cánh vàng, rồi dung hợp với bảo thuật Thanh Thiên Bằng thành một thần thông — Trăng bạc hóa quả trứng vàng ẩn chứa Ma cầm ngủ đông. Sau hai tháng tu hành, người Bổ Thiên các mời nó xuất quan tham dự sự kiện phục sinh Tế Linh, giàn dây Hồ Lô Thượng Cổ đang khô héo sắp chết. Tại cấm địa nhà hộ gia đình Thượng Cổ, Bổ Thiên các hiến nhiều thần vật: huyết nhục của Thần do Các chủ dâng, đất Lam Tinh, Lôi Kiếp dịch của Mộ Viêm, cùng bốn túi bùn cát Bất Lão Tuyền của Nhóc Tỳ. Gốc cây chấn động phát sáng, tinh hoa mặt trời và ngân hà ngoại vực đổ xuống, Tế Linh thức tỉnh với làn sóng sinh mệnh khuếch tán bốn phương. Từ phương xa, ba đại năng — bóng người thiên thần, hung cầm khổng lồ và sinh linh trên thần sơn — dõi theo và bàn về sự tồn vong của Tế Linh, tỏ ý muốn nó chết đi."},{"chuong":180,"tieuDe":"Dung Hợp","tomTat":"Trên một ngọn thần sơn ngoài Bổ Thiên các, một bóng người hào quang dâng trào bước ra đại lộ ánh sáng vàng, lạnh lùng nói đối phương nếu không chết thì quá nghịch thiên, cùng hai bóng người khác lặng lẽ quan sát. Bên trong các, Tế Linh — cây dây leo già suy yếu gần chết — bỗng niết bàn phục sinh, nuốt ánh sáng ngân hà và tinh hoa mặt trời, trổ lộc mầm non với xích thần trật tự lượn quanh, khiến người Bổ Thiên các vui mừng quỳ lạy và tin phục sinh truyền chấn động khắp Đại Hoang; các bóng người và hung cầm bên ngoài lần lượt rút lui. Đêm khuya dưới lục đằng ở Tịnh Thổ, Nhóc Tỳ nghiền ngẫm cốt thư mang từ Tàng Kinh các ra và dung hợp bảo thuật Kim Sí Đại Bằng cùng Thanh Thiên Bằng thành một, uy lực tăng vọt, sau lưng hiện vầng thần nguyệt màu vàng thai nghén Ma cầm Thái Cổ. Nó chấn động nhận ra đây có thể là Côn Bằng — một trong mười đại chim thần hung thú mạnh nhất Thái Cổ — nhưng mới chỉ là khởi đầu. Tế Linh lần đầu mở miệng, xác nhận con đường này đúng, tiết lộ mình sống từ Thượng Cổ nay sinh mệnh khô cạn sắp tọa hóa, phục sinh mạnh mẽ chỉ để Bổ Thiên các không gặp họa ngay, và cảnh báo Hoang vực sẽ đại loạn có thể bắt đầu từ cái chết của nó. Nhóc Tỳ đề nghị cho hai giọt Bất Lão Tuyền nhưng bị từ chối; cuối cùng Tế Linh mọc mầm quấn khối kim cốt lấp lánh phù văn từ lòng đất lên tặng, nói không kém bảo thuật trấn giáo, khiến Nhóc Tỳ nghi ngờ dưới rễ cây còn chôn nhiều cốt thư và thần thông trấn giáo thất lạc."},{"chuong":181,"tieuDe":"Côn Bằng","tomTat":"Nhóc Tỳ trông thấy một khối kim cốt màu vàng lưu chuyển ánh sáng với phù văn không ẩn đi, kích động muốn học ngay nhưng Tế Linh khuyên “dục tốc bất đạt”, chỉ điểm đạo lý bảo thuật rằng phải thông hiểu bản chất phù văn mới là chân chính. Nó chìm vào ngộ pháp hơn tháng, mượn nhiều cốt thư về chim bằng ở Tàng Kinh các, dung hợp quán thông đến mức khiến lão tổ canh cửa thẫn thờ gọi là “tiểu quái vật”, rồi đạt cảnh ngộ đạo trong Động Thiên thai nghén ra Thần Bằng chí cường. Được Tế Linh cho phép nghiên cứu, nó phát hiện khối kim cốt chính là xương Côn Bằng — hậu duệ của Côn Bằng thập cường Thái Cổ — và quyết tái hiện Côn Bằng thuật. Bên ngoài, việc Tế Linh tái sinh khiến Đại Hoang chấn động, khiến Các chủ và cao tầng Bổ Thiên các ủ rủ bí mật hành động vì đại họa sắp tới. Cùng lúc Thạch Nghị thành công bước vào Thánh viện Thượng Cổ, được xem tương lai thành Thần Vương. Trục Lộc thư viện do một nữ chiến thần dẫn đầu đến khiêu chiến, chỉ một người lên sàn đã đánh bại cả đám Thiên Tài doanh; Nhóc Tỳ đến thấy Thanh Phong bình an còn Chu Vũ Hào quấn băng đầy mình, liền đòi đi tái chiến ngay không chờ Vũ Phong."},{"chuong":182,"tieuDe":"Mạnh Mẽ Nghiền Ép","tomTat":"Nhóc Tỳ hô hào cả đám Thiên Tài doanh, dẫn người xông thẳng tới Ngũ Linh nhai — nơi ở của Trục Lộc thư viện — để tính sổ, hung danh của nó lan xa khắp Hư Thần giới lẫn Bách Đoạn sơn. Thiếu niên áo bào tím Thác Bạt Xuyên cưỡi di chủng Thái Cổ Kim Tình Long Giác Sư ra mặt, kiêu ngạo tuyên bố chỉ tọa kỵ đã đủ san bằng cả đám. Nhóc Tỳ tự bước ra, rống áp chế Sư Tử hống, đánh nát con thú rồi triệu đại bàng cánh thần chém đứt đôi nó. Sừng rồng gãy phun máu tươi, Nhóc Tỳ hứng vào bình ngọc dành hết cho Thanh Phong uống làm bảo dược. Thác Bạt Xuyên tức giận hóa Kim Bằng tấn công nhưng bị đấm nổ tung, xuyên thủng mười tám tầng ánh sáng, gãy xương tay, bị cướp bảo cụ đưa cho Thanh Phong rồi ném cho Thiên Tài doanh đánh tiếp; chương hé lộ Nhóc Tỳ đã mở chín Động Thiên — điều chỉ ghi trong sách cổ Nhân tộc. Cuối cùng Nhóc Tỳ nướng thịt di chủng đãi cả doanh, đúng lúc Hạ U Vũ cùng cô gái chiến giáp hoàng kim đến, kinh ngạc phát hiện thịt nướng chính là tọa kỵ của Thác Bạt sư đệ."},{"chuong":183,"tieuDe":"Ba Tên Mập","tomTat":"Đám người Học viện Trục Lộc kéo tới thì đờ người khi thấy đám thiếu niên Bổ Thiên các đang ngồi ăn thịt tọa kỵ di chủng canh cửa của họ; một nữ đệ tử vội nâng Thác Bạt Xuyên đầy máu tươi gãy hơn mười khúc xương dậy. Nhóc Tỳ giải thích Thác Bạt Xuyên xông vào Thiên Tài doanh đánh gãy chân đứt gân mấy sư huynh nên bị đánh bại, còn con di chủng Kim Tình Long Giác Sư bị ăn vì 'nó muốn ăn thịt ta'. Nữ chiến thần giáp vàng phát sáng mến tài sự ngang ngược của Nhóc Tỳ, kể ra gia tộc Thác Bạt là gia tộc Thượng cổ uy chấn Đại Hoang, từng có chí lập quốc nhưng Tế Linh bị một cây dây leo thần giết chết nên thất bại, sau trở lại đỉnh cấp và coi Bổ Thiên các là tử địch. Nhóc Tỳ mời Hạ U Vũ và Nữ chiến thần ăn thịt vàng ươm ẩn chứa tinh hoa thần tính rồi buông lời khuyên hai nàng 'giảm béo', khiến cả hai phẫn nộ lấy bảo cụ đuổi đánh. Nhóc Tỳ lôi cả Tiêu Thiên và Thanh Phong vào cuộc, rồi triển bảo thuật thân phát sáng mọc đôi cánh vàng tốc độ tăng vọt bỏ xa cả hai nhờ đoạt được khối kim cốt Kim Sí Đại Bằng truyền thuyết trong Tàng Kinh các. Hỏa Linh Nhi áo đỏ chạy tới giúp nhưng đúng lúc bị Nhóc Tỳ chê 'béo đến kinh người', khiến ba người con gái đều tức giận khi bị gọi chung là 'Ba tên mập'."},{"chuong":184,"tieuDe":"Quyết Đấu Bằng Thuật","tomTat":"Sau khi trêu chọc hai sư tỷ mập ở Bổ Thiên các, Nhóc Tỳ bỏ chạy nhưng bị Hạ U Vũ tìm ra, bị đánh một trận và buộc phải đứng ra luận bàn giao lưu với đoàn Trục Lộc học viện do Nữ Chiến Thần dẫn đầu. Một thiếu nữ thiên tài Bằng thuật ra tay, nhưng Nhóc Tỳ tay không phá vảy vàng, hóa giải Thần bằng cương phong và Huyễn Bằng thuật, rồi dùng vòng xoáy vàng của bảo thuật Côn Bằng vừa phòng ngự vừa hút phù văn để bắt chân thân và trấn áp nàng. Nữ Chiến Thần giữ lời, truyền cho Nhóc Tỳ một đoạn mật ngữ bảo thuật Bằng tộc, giúp nó thu hoạch rất lớn. Tiếp đó tứ đại thiếu niên cường giả liên thủ dùng sát trận bốn bảo cốt, nhưng bị cặp cánh Côn Bằng chấn cho hộc máu bay ngược và thất bại thảm hại. Nữ Chiến Thần cảm nhận sau lưng Nhóc Tỳ như đại dương có cá phi thăng, xác định đó là Côn Bằng và khiếp sợ tiềm lực của nó. Cuối chương Bổ Thiên các đột nhiên dị biến: bảy tám ngọn linh sơn lún xuống vực đen, đất nứt khe lớn đen thui khởi phát từ nơi ở của dây leo già, khiến Nhóc Tỳ nghi Tế Linh muốn tọa hóa."},{"chuong":185,"tieuDe":"Tế Linh Chiến","tomTat":"Bổ Thiên các đại loạn khi khe nứt lớn màu đen lan tràn như mạng nhện, linh sơn rơi vực sâu, cung điện cổ sụp đổ thành phế tích do tâm địa chấn phát ra từ nơi Tế Linh. Nhóc Tỳ mọc đôi cánh thần vàng óng phi tới cấm địa, thấy dây leo già biến thành đại thụ Hỗn Độn che kín bầu trời, dùng dây leo hóa chiến mâu ngọc bích và hồ lô xanh phá mắt dọc, nổ sừng rồng, đâm thủng đầu lâu một sinh vật hình người cao mấy chục trượng có cánh chim trắng và sừng rồng tím, luyện hóa hoàn toàn thi thể thành ánh sáng và máu năm màu. Sau khi hấp thu, đại thụ thu nhỏ lại thành dây leo và các khe nứt khép lại, linh sơn mọc lên, cung điện tự xây lại như thần tích. Tế Linh báo hiệu bên trong đã suy yếu, sắp tọa hóa, dặn Bổ Thiên các dời đi và bàn việc lưu thần chủng để tái sinh; các chủ và lão tổ bi thương cúi chào. Bên ngoài vạn dặm, một con hung cầm khổng lồ mắt như hai vầng huyết nguyệt tuyên bố sẽ chiếm thần chủng, còn một bóng người thần quang ở thế giới khác lẩm bẩm về danh tiếng Tế Linh. Cuối cùng Nhóc Tỳ toàn tâm tu hành một tháng, tiêu hóa Thần Bằng thuật của Thư viện Trục Lộc và tìm hiểu thấu đáo Côn Bằng cốt, dị tượng hiện biển rộng với trứng vàng-đen nứt ra cá lớn hóa thành bằng bay chín vạn dặm, thành công tái hiện thần thông Thập cường sinh linh Thái cổ, gieo xuống hạt giống bảo thuật cái thế."},{"chuong":186,"tieuDe":"Gấp Rút","tomTat":"Sau hơn một tháng bế quan trong Tịnh Thổ, Nhóc Tỳ tu thành bảo thuật Côn Bằng, nhiều lần hóa thân trải nghiệm một đời loài này, đại thần thông vượt xa bảo thuật Toan Nghê và bước đầu dưỡng thành vô địch thế. Ra ngoài đoàn tụ với Thanh Phong và Nhị Ngốc Tử, nó phát hiện Bóng Lông uống rượu Hầu Nhi say, cơ thể óng ánh ngưng tụ phù văn, nghi ngờ chính là Chu Yếm — hung thú Thái cổ. Đại Hồng Điểu bay hàng trăm vạn dặm qua Đại Hoang tới Bổ Thiên Các bái sư, tự xưng huynh trưởng, khiến Hỏa Linh Nhi tức giận dẫn người vặt sạch lông con quạ. Nhóc Tỳ ngồi xem, quật ngã Hỏa Linh Nhi cướp sạch bảo vật rồi truyền cho Đại Hồng Điểu pháp môn tăng tốc bay của Kim Sí Đại Bằng. Ba tháng đọc kinh văn Tàng Kinh Các, nó nghe Liễu Lão tiết lộ Bổ Thiên Thuật đã thất truyền từ Thượng cổ và Bổ Thiên Các sắp kinh biến. Cuối cùng Nhóc Tỳ lần thứ hai vào linh sơn gặp Lôi Tổ Mộ Viêm xin chỉ điểm Lôi Đạo, được Lôi Tổ khen ngợi và dự đoán sẽ rời Hoang vực ra ngoài tranh bá."},{"chuong":187,"tieuDe":"Lôi Kiếp","tomTat":"Nhóc Tỳ trải qua giai đoạn tu hành sung mãn, mở tiệc với đồng môn và sai Bóng Lông đi trộm rượu lâu năm của Hùng Phi, Trác Vân trưởng lão khiến hai lão nổi giận. Cùng lúc, Bổ Thiên Các phân tán đệ tử tránh đại họa sắp giáng: nhiều sư huynh sư tỷ và Thiên Tài Doanh lần lượt rời đi tới nơi xa lạ, Thanh Phong thì nằng nặc chờ đi cùng Nhóc Tỳ. Nhóc Tỳ bắt đầu tu Lôi Thuật, bị Lôi Tổ Mộ Viêm dùng sét đánh tơi tả cả ngày, buộc dùng thân thể cảm ngộ pháp tắc Lôi Đạo; nó hóa Toan Nghê phản kháng nhưng bị đánh bay, cả người cháy khét. Mượn tia điện tích trong người, Nhóc Tỳ đánh bay Đại Hồng Điểu, Nhị Ngốc Tử rồi quật ngã lục soát Hỏa Linh Nhi, để lại vết cào trên mông nàng. Tới Tàng Kinh các, nó thấy hơn 90% cốt thư đã chuyển đi và được Liễu Lão giữ lại kinh thư chưa xem. Sau một tháng, Nhóc Tỳ chạm được tia sinh cơ trong Lôi Điện — kỳ tích mà chính Mộ Viêm cũng chưa làm được, khiến cả Lôi Tổ và Liễu Lão kinh sợ. Mộ Viêm hứa mấy ngày nữa vào ngày Lôi Vũ sẽ dẫn Nhóc Tỳ đi thu Lôi Kiếp Dịch — thần dịch đoạt thiên địa tạo hóa cực kỳ nguy hiểm."},{"chuong":188,"tieuDe":"Thần Dịch","tomTat":"Ngày Lôi Vũ đến, trời âm u mưa như thác đổ, sấm sét kim xà nối liền trời đất khiến hung cầm mãnh thú Đại Hoang phải ẩn nấp; Lôi Kiếp Dịch chỉ sinh ra khi mưa dông rút và tia điện mỏng dần. Cách Bổ Thiên Các mấy chục dặm, Lôi Tổ Mộ Viêm kéo Nhóc Tỳ bay vào Lôi Điện Cửu Thiên, dặn cậu cảm ứng tia sinh cơ thai nghén trong hủy diệt. Nhóc Tỳ chỉ đúng vị trí, Mộ Viêm chịu phần lớn tia điện để che chở rồi một mình lao vào lôi hải, chiến y hóa tro, cả người cháy đen nứt nẻ, bả vai xuyên thủng lộ xương mà vẫn tiến tới ao thần chiếm một tia sinh cơ. Nhóc Tỳ dùng bảo kính Toan Nghê ổn định đoàn khí tím, giúp Mộ Viêm luyện thành một giọt Lôi Kiếp Dịch đựng vào bình ngọc. Dù thương thế gần chết, Mộ Viêm nhất quyết nhường giọt thần dịch cho Nhóc Tỳ để xây căn cơ Lôi Đạo và uống Hầu Nhi Tửu chữa thương. Nhóc Tỳ hấp thu thần dịch, pháp tắc Lôi Đạo hiển hiện, con Toan Nghê hoàng kim lột xác phủ phù văn màu tím, bảo thuật Toan Nghê trở thành đòn sát thủ chí cương chí cường mang khí tức hủy diệt."},{"chuong":189,"tieuDe":"Tận Thế","tomTat":"Nhóc Tỳ tu thành bảo thuật Lôi Đạo, cả người tỏa nhuệ khí và tia chớp chí cường chí dương, khiến hai đại thần thông lột xác thăng hoa. Mộ Viêm vốn sắp chết vì thương thế được uống Hầu Nhi Tửu nên xương cốt huyết nhục tái tạo, xếp bằng vận công một ngày một đêm thì khôi phục hoàn toàn. Nhóc Tỳ hỏi về Thánh Viện Thượng Cổ, được biết đó là tiểu thế giới truyền từ Thượng Cổ, mỗi trăm năm mở một lần, nay đã đóng vì Thạch Nghị đã tiến vào. Tứ đại tộc Ly-Uyên-Côn-Mông kéo đến Bổ Thiên Các báo thù Nhóc Tỳ, nhưng mấy trăm đệ tử đồng lòng nghênh chiến cùng Lâm Mộc sư huynh, các lão già và Mộ Viêm đích thân xuất thủ giết sạch. Tin dữ truyền tới: ba trong bảy cứ điểm bí mật của Bổ Thiên Các bị phá, đệ tử tinh anh gần như diệt sạch, các chủ phun máu, Mộ Viêm đánh tung linh sơn, Liễu Lão ho ra máu. Tế Linh sinh mệnh sắp cạn quyết định lưu lại Thần Chủng để bảo vệ Bổ Thiên Các tái sinh rồi phóng xích thần che kín trời tuyên chiến. Phương xa Chí Cường Giả kim quang chiếu từ mấy trăm dặm như từ Thiên Giới giáng lâm, vô số sinh linh bao vây Bổ Thiên Các để tranh phần, đại nạn ập đến."},{"chuong":190,"tieuDe":"Khách Đến Từ Thần Sơn","tomTat":"Bổ Thiên Các — một Thánh Địa lớn — sụp đổ, vô số sinh linh Nhân Tộc lẫn dị chủng từ bốn phương tám hướng vây kín chờ vơ vét thần tàng và Đại Cơ Duyên; các lão giả dẫn đệ tử chia mấy chục tổ liều mạng mở đường máu, nhiều người chôn thây. Lão tổ gia tộc Thác Bạt ngự không trên da thú cổ chém một kiếm cắt đứt đại địa giết nhiều đệ tử, bị Lôi tổ Mộ Viêm triệu hoán mây đen tia chớp đánh bay cháy khét. Trên chín tầng trời, ba đại Chí Cường Giả — sinh linh kim quang Nam Vẫn Thần Sơn, Thôn Thiên Tước, Cùng Kỳ — hội tụ tranh đoạt Thần Chủng, tinh hoa cả một đời của Lão Đằng. Có tiếng nói trong bóng tối vạch trần quá khứ: Thôn Thiên Tước từng nuốt lão sư Thiên Nga Cầm Thánh, Cùng Kỳ từng là Tế Linh một Cổ Quốc rồi nuốt sạch dân, còn sinh linh kim quang thực là cường giả gốc Nghi Sơn từng nuốt Khổ Thánh Tiểu Tây Thiên. Lão Đằng thừa nhận mưu giả-yếu vô dụng, chọn quyết chiến phóng dây leo hồ lô lên Cửu Thiên triệu hoán sao băng, nhưng thân khô héo lá xanh biến vàng, sinh mệnh đã đến điểm cuối. Nhóc Tỳ chứng kiến trận chiến chấn động, hồi tưởng lời Liễu Thần rằng ma cầm là Thôn Thiên Tước, hung thú là Cùng Kỳ; Liễu Lão xé tan da hổ chống Bạch Hổ Tây Lăng Thú Sơn; cuối chương một nhóm người dẫn con cháu xông thẳng vào nơi ở Tế Linh, ngửa mặt chờ mong thời khắc tẩy lễ."},{"chuong":191,"tieuDe":"Mưa Thần Linh","tomTat":"Toàn bộ trong ngoài Bổ Thiên Các hỗn chiến, các chủng tộc và thế lực trùng kích tranh Đại Cơ Duyên, máu nhuộm Tàng Kinh Các và linh dược điền; kẻ thù truyền kiếp Thác Bạt tộc và Thú Sơn Tây Lăng ra tay tàn độc muốn diệt sạch Tịnh Thổ. Mộ Viêm (Lôi Tổ) mắt đỏ bừng giết mấy chục cường giả, dùng lôi bạo chuỗi cầu tím, Thập Tinh Quán Nhật và Lôi Thần Chùy, cuối cùng dùng tay xé đôi con cá sấu bạc bá chủ một phương. Liễu Lão đi con đường Nhục Thân Thành Thánh, thi triển Cánh Kim Bằng hóa Kim Sí Đại Bằng, chém đứt chiến mâu răng nanh và phá sát trận, làm nứt vỡ xương trán Bạch Hổ khiến nó chết. Từ chín tầng trời rơi xuống mưa ánh sáng — tinh hoa thần thánh của Tế Linh (Lão Đằng) sắp tọa hóa, thành Thiên Đại Cơ Duyên gột rửa thiếu niên; Vũ Phong huynh muội và con cháu Vương Hầu thuộc Thiên Tài Doanh huyết chiến tranh vị trí tốt. Tế Linh vốn bảo vệ Tịnh Thổ từ Thượng Cổ vì một lời hứa, đã trải qua nhiều huyết chiến và xây thông đạo lần thứ bảy thất bại, nói lời tạm biệt rồi tọa hóa. Sau khi Tế Linh chết, nhiều cường giả cựu đệ tử như bộ lạc Hỏa Tê, Linh Uy Hầu, Kỳ Sơn tộc chủ, bộ lạc Xích Dương, Lăng Thiên Hầu và Chiến Vương Thạch Quốc bất chấp hiểm nguy quay về cứu viện, khiến các chủng tộc xâm lấn kinh hãi."},{"chuong":192,"tieuDe":"Trên Dưới Một Lòng","tomTat":"Trong lúc Tịnh Thổ nguy cấp, các cựu đệ tử Bổ Thiên Các từ khắp nơi trở về hô vang quyết tử chiến, khiến sĩ khí sôi trào và đại chiến bùng nổ khắp chiến trường. Lăng Thiên Hầu bắn nổ một con quạ đen Thái Cổ của Cầm Tộc, Tộc chủ Kỳ Sơn dùng bảo ấn nghiền nát địch, còn Chiến Vương phát sáng như mặt trời búng nát thanh kiếm xanh rồi đấm nổ tung lão quái vật cấp lão tổ có đại thù với các chủ. Các chủ Bổ Thiên Các thi triển Thần Bằng Thuật hóa thành Đại Bằng vàng xé nát con Ngân Giao khổng lồ, nhưng phe địch lại đưa ra Hoàng Kim Thú xưng Thần Bộc từ Thái Cổ Thần Sơn khiến cục diện càng tuyệt vọng. Trên chín tầng trời, Thôn Thiên Tước và Cùng Kỳ vây định luyện Tế Linh thành đan dược khi Thần Đằng đã khô vàng kiệt lực; Lão Đằng dốc sức trận cuối trọng thương cả hai rồi cạn kiệt, cả người cháy hóa thành mưa Thần Linh. Nhóc Tỳ ôm bi thương cầm Kiếm Gãy và Tiểu Tháp xung phong, kiếm phát sáng triệu xuất Quỷ Gia hiện thân trước tất cả mọi người, vọt lên chém đứt móng vuốt Thôn Thiên Tước và rống như Ma Thần. Trước khi tan biến, Tế Linh nhìn Quỷ Gia và thừa nhận chính ông là người đã trồng và ban cho nó sinh mệnh, rồi mờ nhạt biến mất trong màn mưa ánh sáng."},{"chuong":193,"tieuDe":"Thủy Tổ","tomTat":"Tế Linh (Thần Đằng/Lão Đằng) tàn lụi hóa thành mưa Thần Linh, khiến môn nhân Bổ Thiên Các đau đớn gào khóc; ông lão tuổi cả đời thủ hộ họ nay Thần Hỏa tắt. Ông lão tóc xám (Quỷ Gia) phẫn nộ cầm Kiếm Gãy đại chiến tứ đại sinh linh — chém đứt mỏ rồi cánh Thôn Thiên Tước, móng vuốt rồi cánh tay Cùng Kỳ, cánh tay sinh linh Nghi Sơn và cẳng chân cường giả Nam Vẫn Thần Sơn. Tế Linh để lại Thần Chủng hồ lô xanh tràn khí Hỗn Độn, mục tiêu tranh đoạt của bốn sinh linh. Ông lão tiết lộ mình là kẻ bị ruồng bỏ đã khai sáng Bổ Thiên Các — tức Thủy Tổ khai phái, khiến Mộ Viêm, Liễu Lão và mọi người chấn động. Nhân lúc tỉnh táo, Thủy Tổ ném Thần Chủng qua thông đạo vàng đi cuối chân trời để bảo tồn truyền thừa, rồi vẽ phù văn phong ấn giam tứ đại sinh linh và lệnh môn nhân rời đi. Tiểu Tháp của Nhóc Tỳ âm thầm bay ra nuốt tứ chi bị chém đứt của bốn sinh linh mà không ai hay; chuôi cổ kiếm cắm trên đầu Thủy Tổ phát tác khiến lão lảo đảo, máu đen phụt ra, thần trí lúc tỉnh lúc mê nhưng vẫn tiếp tục vồ giết địch."},{"chuong":194,"tieuDe":"Phá Vòng Vây","tomTat":"Trên chín tầng trời, Thủy Tổ tóc xám của Bổ Thiên các hiện thân từ tàn thi di niệm, người-kiếm hợp nhất dùng kiếm gãy trọng thương cả tứ đại Chí Cường giả: chém cánh Thôn Thiên Tước, chặt sừng xuyên ngực Cùng Kỳ, cắt vòng thần Nghi Sơn, chặt cốt phiên cường giả Thần Sơn Nam Vẫn — nhưng đầu ông bị cổ kiếm cắm xuyên, xương sọ nứt máu đen, rơi vào nguy kịch. Nhận ra Thủy Tổ chỉ là tàn thi đã chết từ Thượng Cổ, kẻ địch hết sợ và vây công lại. Được Lăng Thiên hầu, Kỳ Sơn tộc chủ, Chiến Vương cứu viện, Các chủ ra lệnh môn nhân phân tán phá vây, hẹn trùng kiến Bổ Thiên các; Mộ Viêm và Liễu lão mở đường máu. Hoàng Kim thú, Thác Bạt tộc và Phi Mãng Vương chặn nhiều hướng; Các chủ cùng Đào Dã điều khiển hồ lô vàng chí bảo tỏa khí Hỗn Độn chấn nát cổ thú và chấn bay Thần Bộc. Hỏa Linh Nhi gọi Phụ hoàng cầu cứu, Nhân Hoàng Hỏa Quốc ngồi xe chiến bùng sáng phong ấn núi cứu mấy trăm môn nhân, nổ cánh tay lão tổ Thác Bạt tộc và giết con cháu họ. Nhóc Tỳ chậm một bước lỡ mất xe chiến, đành cưỡi Đại Hồng Điểu bay tầng thấp cùng Thanh Phong, Nhị Ngốc Tử trốn chạy, bị truy đuổi rồi tạm thoát; cuối chương một tia sáng đen xuất hiện và thanh kiếm gãy rơi xuống."},{"chuong":195,"tieuDe":"Đại Kiếp Nạn Chấm Dứt","tomTat":"Giữa thập phương loạn chiến, Nhóc Tỳ thu hồi thanh kiếm gãy chí bảo từng chặt Thôn Thiên Tước và chém Cùng Kỳ, phát hiện rỉ sét đã biến thành những vết máu đỏ sậm khiến nó lo lắng cho Quỷ gia. Nó chọn cách trôi theo dòng, thu Thanh Phong, Nhị Ngốc Tử và Đại Hồng Điểu vào túi Càn Khôn để tìm đường vượt ải. Trên đường chứng kiến Kim Sư vương của Thú Sơn Tây Lăng tuyên bố tuyệt diệt Bổ Thiên các, trọng thương Hắc Hổ, và hai trưởng lão Bổ Thiên các tự bạo giữa đám địch cứu đệ tử. Dù cải trang bằng bảo thuật Bóng Lông và mặc y phục Thác Bạt tộc, Nhóc Tỳ vẫn bị bốn đại tộc lần theo nhờ cỏ U Lan dính trên người. Nó ra tay chém giết cường giả Vũ tộc khi Vũ Phong phản sư môn ép trưởng lão giao bảo thuật câu thông tinh hoa của nước, cố ý lộ thân phận Hùng Hài Tử để dụ truy đuổi rồi thoát. Nhóc Tỳ đau xót thấy Hùng Phi và Trác Vân trưởng lão chết thảm, còn Lâm Mộc sư huynh triển Nhiên Huyết Thông Thiên công tự sát chặn hậu. Đại kiếp nạn kéo dài một ngày một đêm chấm dứt, Nhóc Tỳ trốn thoát thành công, quẹt lệ rời vùng Tịnh Thổ nhuốm máu đón bình minh."},{"chuong":196,"tieuDe":"Lạc Hoàng Lĩnh","tomTat":"Trong buổi bình minh sương mù ngũ sắc, Nhóc Tỳ dứt khỏi mảnh đất thương tâm Tịnh Thổ, chạy đi như sao chổi dẫn nhóm về Thạch thôn. Tin Bổ Thiên các bị diệt hoàn toàn chấn động toàn Đại Hoang; nguyên do là Thần Chủng — chí bảo dây leo già thai nghén từ Thượng Cổ khiến các Chí Cường giả của Thác Bạt tộc, Thú Sơn Tây Lăng, Thái Cổ Thần Sơn, Nghi Sơn và Thần Sơn Nam Vẫn ra tay. Cao tầng Tịnh Thổ cùng thiên tài như Lâm Mộc, Ngũ Phong đều chết trận, chỉ nhóm được Nhân Hoàng Thạch quốc cứu thoát nạn. Thanh Phong khóc thương rồi thề báo thù, Nhị Ngốc Tử khuyên nén bi thương; nhóm giết linh khuyển tứ đại gia tộc và thoát truy dấu vì mùi cỏ U Lan đã phai. Nhóc Tỳ tính đường về qua Thạch Quốc và Tây Cương, nhắc lại thù riêng với Vũ tộc gồm việc mất Chí Tôn cốt và chân Thanh Phong bị hãm hại tàn phế. Chưa đủ sức đánh Vũ tộc, nhóm quyết cướp Lạc Hoàng lĩnh giàu linh dược trên đường đi. Bóng Lông mang túi da thú và kiếm gãy hóa vệt sáng vàng đột nhập vườn linh dược canh gác nghiêm ngặt, trong lúc Vũ tộc theo lệnh Vũ Vương điên cuồng truy bắt một thần vật quý hơn mấy chục cây linh dược; cuối cùng Bóng Lông trở ra an toàn với cái bụng no căng tròn phải lăn ra ngoài."},{"chuong":197,"tieuDe":"Bát Trân Kê","tomTat":"Bóng Lông trộm về mười một cây linh dược từ Lạc Hoàng lĩnh của Vũ tộc, khiến Nhóc Tỳ đau xót vì cả lĩnh bị phá tan. Bóng Lông cùng Đả Thần Thạch (Ngoan Thạch) đột nhập cướp một con sinh linh nắm pháp môn hành Thổ mà cao thủ Vũ tộc nhiều lần bắt hụt; Đả Thần Thạch còn hút tinh hoa đất màu máu. Vật cướp được hóa ra là con gà đất mập ú, được Nhị Ngốc Tử nhận ra chính là Bát Trân Kê — thần trân thời Thái Cổ đẻ trứng ngang linh dược. Nhóc Tỳ cấm cả nhóm ăn, quyết đưa về Thạch thôn nuôi để người trong thôn có trứng dùng. Vũ vương thịnh nộ khi bị trộm mất, cần máu huyết cổ xưa của Bát Trân Kê, tin chấn động cả Hoàng Đô Thạch quốc. Nhóm cưỡi Đại Hồng Điểu vừa luyện Thần Bằng thoát truy sát, băng Đại Hoang qua sông Thái Âm về gần Thạch thôn trong xúc động."},{"chuong":198,"tieuDe":"Trở Lại Thạch Thôn","tomTat":"Nhóc Tỳ và Thanh Phong xúc động trở về Thạch thôn sau hai năm rời đi. Cách thôn mấy dặm, nhóm phát hiện tàn tích chiến đấu với bảo cụ uy lực vượt cả Giao Long tiễn khiến Nhóc Tỳ hoảng sợ lo cho thôn. May thay Thạch thôn bình an nhờ cây Liễu Thần trước thôn từng bị sét đánh cháy nay hồi sinh mọc cành non tỏa khí Hỗn Độn, làm Tế Linh giữ thôn an lành. Nhị Ngốc Tử kinh sợ nhận ra Liễu Thần là thần thánh thông thiên động địa. Ba con thần điểu Tử Vân, Đại Bằng, Tiểu Thanh — con của Thanh Lân Ưng — mạnh ngang di chủng nhờ ngủ dưới gốc Liễu Thần; Thanh Lân Ưng cũng vào sâu Đại Hoang khổ tu. Cả tộc nhân kéo ra ôm khiêng đón Nhóc Tỳ và Thanh Phong; tộc trưởng Thạch Vân Phong tóc bạc nhiều xúc động nắm tay cậu. Cuối cùng Hổ thẩm tưởng Nhị Ngốc Tử là chim quà, xách cổ định làm món gà hầm thuốc bắc."},{"chuong":199,"tieuDe":"Chương 199","tomTat":"Nhóc Tỳ và Thanh Phong về đến Thạch thôn, phải can ngăn các đại thẩm định hầm thịt Nhị Ngốc Tử và Đại Hồng Điểu vì tưởng là bảo dược. Đám bạn thân thuở nhỏ đã đột phá tu vi mạnh mẽ: Lâm Hổ thúc và Phi Giao thúc lên Động Thiên cảnh, còn Đại Tráng, Nhị Mãnh, Bì Hầu vào Bàn Huyết cảnh nhờ tộc trưởng dạy cốt văn và ăn huyết nhục Toan Nghê cùng bảo huyết Tế Linh. Bất ngờ hơn, Đại Tráng đã cưới Báo tỷ và có con một tuổi, khiến Nhóc Tỳ được lên chức thúc thúc. Nhóc Tỳ tặng cháu nhỏ nhân sâm Tuyết Ngọc, rồi lấy từ túi Càn Khôn hơn ba mươi chín cây linh dược cùng đất thần Bất Lão Tuyền trồng khắp thôn để cải tạo linh khí, biến Thạch thôn thành thần thổ khiến cả thôn chấn động. Cuối cùng cây Liễu Thần đầu thôn lay động khen cơ duyên Nhóc Tỳ không nhỏ, và cậu hứa sẽ tặng Liễu Thần lễ vật hiếm."},{"chuong":200,"tieuDe":"Nơi Ký Thác Tâm Linh","tomTat":"Nhóc Tỳ mở túi Càn Khôn dâng toàn bộ sáu túi thần thổ Bất Lão Thần Tuyền và một giọt Bất Lão Tuyền cho Liễu Thần, giúp cây hồi phục nhờ phân giải thần tính bất hủ, cành cây càng lớn mạnh. Cậu còn lấy ra Thái Nhất Chân Thủy được Liễu Thần định giá là vật dẫn nấu thánh dược, tế luyện chí bảo, giá trị kinh người; đồng thời chia Bất Lão Tuyền cho tộc lão tăng thọ. Liễu Thần dặn Nhóc Tỳ điều chỉnh trạng thái chuẩn bị tẩy lễ trước 12 tuổi. Nhóc Tỳ kể chuyện hai năm, để lộ tin Bổ Thiên các bị diệt khiến Thanh Phong đỏ mắt nhớ sư huynh sư tỷ chết trận. Thạch Lâm Hổ kể thổ phỉ đến vì thần tàng của Chí Tôn đã bị Liễu Thần giết sạch một năm trước. Đội săn về, thú một sừng Tiểu Bạch đã tiến hóa thành hung thú chân chính mang huyết thống Thiên Mã Thái Cổ. Nhóc Tỳ mở thịnh yến thịt di chủng Thái Cổ và rượu Hầu Nhi, có người đột phá tại tiệc; ở Thạch thôn cậu trở lại thành đứa trẻ hồn nhiên mất hết tính hung tàn."}];
